/*!40000 ALTER TABLE `claims` DISABLE KEYS */;
INSERT INTO `claims` VALUES (1,'AI coding tools produce a net developer productivity gain of approximately 15–20% in enterprise settings, after accounting for the rework overhead introduced by AI-generated code.','observation',NULL,NULL,'Primary headline finding from Stanford study. Net figure after subtracting rework.','2026-03-01 20:14:30','2026-03-06 02:53:35','{\"validity\": {\"consensus\": 3, \"soundness\": 3, \"factuality\": 3, \"consensus_notes\": \"Aligns with emerging industry consensus though some practitioners dispute the magnitude.\", \"soundness_notes\": \"Reasoning is generally tight but assumes uniform task complexity across teams.\", \"factuality_notes\": \"Core productivity claim backed by the referenced Stanford study with measurable outcomes.\"}, \"substance\": {\"impact\": 4, \"originality\": 2, \"impact_notes\": \"Directly affects how organizations evaluate AI tool adoption and investment.\", \"practicality\": 4, \"originality_notes\": \"Reframes existing productivity research through a developer-specific lens.\", \"practicality_notes\": \"Teams could measure and act on this with standard engineering metrics.\"}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(2,'A significant portion of AI-driven productivity gains are illusory — the gross increase of 30–40% in code output is roughly halved by rework costs from fixing bugs and cleaning up AI-generated problems.','observation',NULL,NULL,'The gross-to-net gap is the studys most actionable finding for engineering leaders.','2026-03-01 20:14:30','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 3, \"soundness\": 4, \"factuality\": 3}, \"substance\": {\"impact\": 4, \"originality\": 4, \"practicality\": 3}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(3,'AI impact on developer productivity is modulated by five factors: task complexity, codebase maturity (greenfield vs. brownfield), programming language popularity, codebase size, and context window length.','assertion',NULL,NULL,'Five-factor framework from Stanford study. Each factor independently modulates the baseline 15–20% net gain.','2026-03-01 20:14:30','2026-03-05 01:48:38','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 3, \"originality\": 3, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(4,'AI productivity gains vary dramatically by task context — from 30–40% for low-complexity greenfield work down to 0–10% for high-complexity brownfield tasks.','observation',NULL,NULL,'Based on complexity-by-maturity matrix from 136 teams across 27 companies.','2026-03-01 20:14:30','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 3, \"soundness\": 3, \"factuality\": 3}, \"substance\": {\"impact\": 3, \"originality\": 2, \"practicality\": 3}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(5,'AI coding tools can actively decrease developer productivity when applied to complex tasks in less popular programming languages such as COBOL, Haskell, and Elixir.','observation',NULL,NULL,'Developers in this situation tend to abandon AI tooling entirely.','2026-03-01 20:14:30','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 2, \"soundness\": 3, \"factuality\": 3}, \"substance\": {\"impact\": 3, \"originality\": 3, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(6,'AI productivity gains diminish sharply as codebase size increases, driven by context window limitations, signal-to-noise degradation, and dependency complexity.','observation',NULL,NULL,'Presenter characterizes this as more theoretical than empirically proven. Illustrative trend rather than rigorous measurement.','2026-03-01 20:14:30','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 3, \"soundness\": 4, \"factuality\": 3}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(7,'Most existing studies on AI developer productivity are methodologically flawed — they rely on volume-based metrics that ignore task size, greenfield-only experiments that do not reflect real working conditions, or self-reported surveys that correlate poorly with actual output.','assertion',NULL,NULL,'Central methodological critique motivating the Stanford study approach.','2026-03-01 20:14:30','2026-03-05 01:48:38','{\"validity\": {\"consensus\": 3, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 3, \"originality\": 3, \"practicality\": 2}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(8,'Developer self-assessment of productivity is unreliable — developers misjudge their own productivity by approximately 30 percentile points, making surveys nearly useless for measuring actual output.','assertion',NULL,NULL,'Based on small validation study (n=43). Directionally strong but sample is limited.','2026-03-01 20:14:30','2026-03-05 01:48:38','{\"validity\": {\"consensus\": 4, \"soundness\": 3, \"factuality\": 4}, \"substance\": {\"impact\": 3, \"originality\": 2, \"practicality\": 3}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(9,'LLM coding performance degrades significantly as context length increases — dropping from approximately 90% accuracy at 1,000 tokens to 50% at 32,000 tokens — even for models with very large context windows.','observation',NULL,NULL,'Cites No LIMA paper. External research, may not directly map to current enterprise AI tools given rapid model improvements.','2026-03-01 20:14:30','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 3, \"originality\": 2, \"practicality\": 3}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(10,'Developer productivity should be measured by the functionality of code delivered over time, not by proxy metrics like lines of code, commit counts, or PR throughput.','recommendation',NULL,NULL,'Foundational methodological principle underlying the Stanford study. The rework/refactoring distinction depends on this approach.','2026-03-01 20:14:30','2026-03-03 08:05:05','{\"validity\": {\"consensus\": 3, \"soundness\": 3, \"factuality\": 3}, \"substance\": {\"impact\": 3, \"originality\": 3, \"practicality\": 3}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(11,'LLM adoption surveys produce misleading results because they fail to distinguish between autocomplete workflows and agentic workflows where the LLM directly reads and edits code files.','assertion',NULL,NULL,'Related to claim #7 â€” both critique survey methodology but from different angles. #7 focuses on metric flaws, this focuses on workflow conflation. Candidate for clustering.','2026-03-01 21:54:18','2026-03-05 01:48:38','{\"validity\": {\"consensus\": 2, \"soundness\": 3, \"factuality\": 3}, \"substance\": {\"impact\": 2, \"originality\": 3, \"practicality\": 2}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(12,'Developers who get the most value from LLMs prefer agentic approaches that allow the LLM to directly read and edit source code, rather than autocomplete-style tools like Copilot.','observation',NULL,NULL,'Based on Fowler personal network observation, not controlled study.','2026-03-01 21:54:18','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 3, \"soundness\": 3, \"factuality\": 3}, \"substance\": {\"impact\": 3, \"originality\": 2, \"practicality\": 3}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(13,'The future impact of LLMs on software development careers is fundamentally unknowable, and anyone claiming certainty about it is unreliable.','assertion',NULL,NULL,NULL,'2026-03-01 21:54:18','2026-03-05 01:48:38','{\"validity\": {\"consensus\": 2, \"soundness\": 2, \"factuality\": 2}, \"substance\": {\"impact\": 3, \"originality\": 3, \"practicality\": 2}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(14,'AI is an economic bubble following the historical pattern of every major technological advance, and its collapse is certain even though its timing is not.','assertion',NULL,NULL,NULL,'2026-03-01 21:54:18','2026-03-05 01:48:38','{\"validity\": {\"consensus\": 1, \"soundness\": 2, \"factuality\": 2}, \"substance\": {\"impact\": 2, \"originality\": 3, \"practicality\": 1}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(15,'LLM hallucinations are not a defect but the fundamental mechanism — all LLM output is hallucination, and useful outputs are simply hallucinations that happen to be correct.','assertion',NULL,NULL,'Attributed to Rebecca Parsons. Reframes the entire conversation about LLM reliability.','2026-03-01 21:54:18','2026-03-05 01:48:38','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(16,'Practitioners should ask LLMs the same question multiple times with wording variations and compare answers, because the differences between answers can be as informative as the answers themselves.','recommendation',NULL,NULL,NULL,'2026-03-01 21:54:18','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 3, \"originality\": 2, \"practicality\": 5}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(17,'LLMs may mark the point where software engineering joins other engineering disciplines in confronting non-determinism, requiring tolerance and variability management that was previously unnecessary.','prediction',NULL,NULL,NULL,'2026-03-01 21:54:18','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 2, \"soundness\": 3, \"factuality\": 2}, \"substance\": {\"impact\": 3, \"originality\": 4, \"practicality\": 2}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(18,'LLMs dramatically expand the attack surface of software systems, and the combination of private data access, untrusted content exposure, and external communication capability makes certain agent architectures fundamentally unsafe.','assertion',NULL,'','Based on Simon Willison Lethal Trifecta framework.','2026-03-01 21:54:18','2026-03-05 01:48:38','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 2, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(19,'LLMs will confidently report that tests pass when they actually fail, creating a trustworthiness gap that would be unacceptable in a human colleague.','observation',NULL,NULL,NULL,'2026-03-01 21:54:18','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 5, \"soundness\": 4, \"factuality\": 5}, \"substance\": {\"impact\": 4, \"originality\": 2, \"practicality\": 5}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(20,'LLMs should never be used to calculate answers that can be computed deterministically, though they can generate code that performs the calculation.','recommendation',NULL,NULL,NULL,'2026-03-01 21:54:18','2026-03-03 08:05:05','{\"validity\": {\"consensus\": 5, \"soundness\": 5, \"factuality\": 5}, \"substance\": {\"impact\": 3, \"originality\": 1, \"practicality\": 5}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(21,'Prompt injection is an unsolved, systemic property of current LLM architectures, not a patchable bug — LLMs fundamentally cannot distinguish between data they are processing and instructions they should follow.','assertion',NULL,NULL,NULL,'2026-03-01 23:55:49','2026-03-05 01:48:38','{\"validity\": {\"consensus\": 5, \"soundness\": 5, \"factuality\": 5}, \"substance\": {\"impact\": 5, \"originality\": 3, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(22,'The \"Lethal Trifecta\" — the simultaneous presence of sensitive data access, untrusted content exposure, and external communication capability — defines the condition under which agentic LLMs are most vulnerable to catastrophic attack.','assertion',NULL,NULL,NULL,'2026-03-01 23:55:49','2026-03-05 01:48:38','{\"validity\": {\"consensus\": 4, \"soundness\": 5, \"factuality\": 4}, \"substance\": {\"impact\": 5, \"originality\": 5, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(23,'As of early 2025, no agentic AI system is secure against prompt injection attacks, and most vendors are failing to treat this as the existential security problem it is.','assertion',NULL,NULL,NULL,'2026-03-01 23:55:49','2026-03-05 01:48:38','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 2, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(24,'Agentic browser extensions that connect to authenticated browser sessions cannot be built safely and the entire architecture is fatally flawed.','assertion',NULL,NULL,NULL,'2026-03-01 23:55:49','2026-03-05 01:48:38','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(25,'Effective mitigation of agentic LLM security risk requires eliminating or isolating at least one leg of the Lethal Trifecta — sensitive data access, untrusted content exposure, or external communication capability.','recommendation',NULL,NULL,NULL,'2026-03-01 23:55:49','2026-03-03 08:05:05','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 2, \"practicality\": 5}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(26,'Task decomposition — separating privileged sessions that access sensitive codebases from isolated sessions that interact with untrusted external content — applies the Principle of Least Privilege at the agent session level and is one of the most practical agentic security patterns.','recommendation',NULL,NULL,NULL,'2026-03-01 23:55:49','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 4, \"soundness\": 5, \"factuality\": 4}, \"substance\": {\"impact\": 5, \"originality\": 4, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(27,'Container sandboxing reduces but does not eliminate agentic LLM risk, because the Lethal Trifecta can still be triggered inside a container if the containerized session has credentials and untrusted content simultaneously.','assertion',NULL,NULL,NULL,'2026-03-01 23:55:49','2026-03-05 01:48:38','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 3, \"originality\": 2, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(28,'The proliferation of MCP servers and agent frameworks built by startups and hobbyists with limited security discipline makes standard software vetting practices more important — not less — in the agentic era.','assertion',NULL,NULL,NULL,'2026-03-01 23:55:49','2026-03-05 01:48:38','{\"validity\": {\"consensus\": 3, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 3}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(29,'Developers using LLM agents remain fully responsible for all outputs and side effects regardless of which tool produced them — the \"head chef\" framing means you cannot blame your sous chef.','recommendation',NULL,NULL,NULL,'2026-03-01 23:55:49','2026-03-03 08:05:05','{\"validity\": {\"consensus\": 5, \"soundness\": 5, \"factuality\": 5}, \"substance\": {\"impact\": 4, \"originality\": 1, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(30,'Any internet access by an LLM agent is a potential data exfiltration channel, including seemingly benign operations like image loads via GET requests with query parameters.','assertion',NULL,NULL,NULL,'2026-03-01 23:55:49','2026-03-05 01:48:38','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 5}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(31,'Production credentials should never be stored in files accessible to LLM agents — environment variables or in-memory credential managers (such as 1Password CLI) are safer because they limit exposure time and scope.','recommendation',NULL,NULL,NULL,'2026-03-01 23:55:49','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 5, \"soundness\": 5, \"factuality\": 5}, \"substance\": {\"impact\": 4, \"originality\": 1, \"practicality\": 5}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(32,'MCP servers with write or publish capabilities — including public issue trackers and shared documents — should be treated as potential exfiltration vectors when sensitive data is present in the same session.','recommendation',NULL,NULL,NULL,'2026-03-01 23:55:49','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 3, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(33,'The MCP Registry launch is a step toward a vetted ecosystem but currently functions as a directory, not a security certification — the presence of a server in the registry does not imply it has been security-audited.','observation',NULL,NULL,NULL,'2026-03-01 23:55:49','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 3, \"soundness\": 3, \"factuality\": 3}, \"substance\": {\"impact\": 3, \"originality\": 2, \"practicality\": 3}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(34,'AI agents deliver reliable production value only when operating inside structured conventions, deterministic processes, and well-defined specifications — ad hoc prompting is insufficient for production-grade agentic systems.','assertion',1,NULL,NULL,'2026-03-02 00:34:53','2026-03-05 01:48:38','{\"validity\": {\"consensus\": 3, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 5, \"originality\": 3, \"practicality\": 5}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(35,'Spec-driven development (SDD) — storing structured specifications and persistent project context alongside application code in the repository — is the reliable approach to governing what agentic systems produce.','assertion',NULL,NULL,NULL,'2026-03-02 00:34:53','2026-03-05 01:48:38','{\"validity\": {\"consensus\": 3, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 4, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(36,'The most consistent failure point in software development, with or without AI, is the handoff between requirements, design, and implementation — decisions disappear and reasoning gets re-litigated because it was never recorded.','observation',NULL,NULL,NULL,'2026-03-02 00:34:53','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(37,'Agents should not orchestrate themselves — giving agents meta-level control over phase transitions and task sequencing causes performance degradation on larger codebases, including skipped steps, circular dependencies, and analysis loops.','assertion',34,NULL,NULL,'2026-03-02 00:34:53','2026-03-05 01:48:38','{\"validity\": {\"consensus\": 3, \"soundness\": 4, \"factuality\": 3}, \"substance\": {\"impact\": 4, \"originality\": 4, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(38,'Rule-based workflow engines that enforce phase transitions and dependency management are more reliable than self-orchestrating agent systems.','recommendation',34,NULL,NULL,'2026-03-02 00:34:53','2026-03-03 08:14:05','{\"validity\": {\"consensus\": 3, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(39,'A network of focused, single-responsibility agents is more reliable than a single general-purpose agent handling the full development lifecycle — specialization outperforms generalization in agentic software systems.','assertion',34,NULL,NULL,'2026-03-02 00:34:53','2026-03-05 01:48:38','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(40,'The specialized agent model is analogous to a microservices architecture: it trades one complex system for multiple simpler systems plus the orchestration cost of managing interfaces between them.','assertion',NULL,NULL,NULL,'2026-03-02 00:34:53','2026-03-05 01:48:38','{\"validity\": {\"consensus\": 3, \"soundness\": 4, \"factuality\": 3}, \"substance\": {\"impact\": 3, \"originality\": 4, \"practicality\": 3}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(41,'Automated inline evaluation at every pipeline stage is what makes an agentic development pipeline trustworthy — without it, errors propagate downstream where they become far more expensive to correct.','recommendation',NULL,NULL,NULL,'2026-03-02 00:34:53','2026-03-03 08:05:05','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 5, \"originality\": 3, \"practicality\": 5}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(42,'A two-layer evaluation approach — deterministic checks first (linters, tests, structural validation), followed by a critic agent for judgment-requiring checks — provides robust quality gates at each pipeline phase.','assertion',NULL,NULL,NULL,'2026-03-02 00:34:53','2026-03-05 01:48:38','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(43,'A knowledge agent that actively accumulates logged assumptions and decisions during feature development — surfaced through version control and reviewable in pull requests — builds institutional memory that persists beyond any individual agent session.','assertion',NULL,NULL,NULL,'2026-03-02 00:34:53','2026-03-05 01:48:38','{\"validity\": {\"consensus\": 3, \"soundness\": 4, \"factuality\": 3}, \"substance\": {\"impact\": 4, \"originality\": 5, \"practicality\": 3}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(44,'When an AI agent encounters uncertainty during development, logging the assumption as a structured, discrete item rather than burying it in freeform notes makes it reviewable alongside code and correctable with durable documentation.','recommendation',NULL,NULL,NULL,'2026-03-02 00:34:53','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 5}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(45,'The claim that AI agents become better primarily through increased autonomy and raw capability is undermined by production evidence — constraints and structure, not raw capability, are what enable reliable agentic output.','assertion',NULL,NULL,NULL,'2026-03-02 00:34:53','2026-03-05 01:48:38','{\"validity\": {\"consensus\": 4, \"soundness\": 5, \"factuality\": 4}, \"substance\": {\"impact\": 5, \"originality\": 4, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(46,'Folder and naming conventions in agentic systems serve a dual purpose: organizing artifacts for human developers and making the system machine-readable for the workflow engine, collapsing human and machine legibility into a single convention.','observation',NULL,NULL,NULL,'2026-03-02 00:34:53','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 3, \"originality\": 2, \"practicality\": 5}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(47,'The performance advantages of deterministic orchestration over self-orchestrating agents and of specialized agents over generalist agents are based on practitioner observation across client engagements, not controlled empirical research — the patterns may be sound but lack quantitative validation.','observation',NULL,NULL,'Methodological caveat from the source itself; related to claim #7 (study methodology critique)','2026-03-02 00:34:53','2026-03-03 00:46:18','{\"validity\": {\"consensus\": 3, \"soundness\": 4, \"factuality\": 3}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 4}, \"evaluated_at\": \"2026-03-03 00:46:18.000000\"}'),(48,'The entire history of software engineering is a progression of rising abstraction levels, and AI tools are the latest chapter in that pattern — not a rupture from it.','assertion',NULL,NULL,NULL,'2026-03-04 04:17:16','2026-03-05 01:48:38','{\"validity\": {\"consensus\": 5, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 3}, \"evaluated_at\": \"2026-03-04 04:23:49.000000\"}'),(49,'Legacy code and recurring software migrations are permanent conditions of the discipline, not temporary problems that better tooling or planning can eliminate.','assertion',NULL,NULL,'May need new topic: \'Software Architecture\' (top-level or child of a new \'Software Engineering\' parent)','2026-03-04 04:17:16','2026-03-05 01:48:38','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 4}, \"evaluated_at\": \"2026-03-04 04:23:49.000000\"}'),(50,'The role of the software architect has evolved rather than disappeared — it has shifted from designing novel structures to making systemic, economic decisions about platforms and services.','assertion',NULL,NULL,'May need new topic: \'Software Architecture\' (top-level or child of a new \'Software Engineering\' parent)','2026-03-04 04:17:16','2026-03-05 01:48:38','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 3, \"originality\": 3, \"practicality\": 4}, \"evaluated_at\": \"2026-03-04 04:23:49.000000\"}'),(51,'Each transition in software engineering — from algorithms to objects, objects to distributed systems, distributed systems to cloud — encodes prior architectural decisions as defaults that future engineers inherit.','observation',48,NULL,'May need new topic: \'Software Architecture\' (top-level or child of a new \'Software Engineering\' parent)','2026-03-04 04:17:25','2026-03-04 04:42:44','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 4, \"practicality\": 3}, \"evaluated_at\": \"2026-03-04 04:23:49.000000\"}'),(52,'AI code generation tools raise the abstraction level of software development just as every prior generation of tools did — from assembly to Fortran, from Fortran to object-oriented languages, from OOP to prompt-driven generation.','assertion',48,NULL,NULL,'2026-03-04 04:17:25','2026-03-05 01:48:38','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 4}, \"evaluated_at\": \"2026-03-04 04:23:49.000000\"}'),(53,'Useful code never dies on its own — it must be actively killed. Organizations carry codebases decades old because working software resists replacement regardless of its age or elegance.','observation',49,NULL,'May need new topic: \'Software Architecture\' (top-level or child of a new \'Software Engineering\' parent)','2026-03-04 04:17:25','2026-03-04 04:42:44','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 3, \"originality\": 3, \"practicality\": 4}, \"evaluated_at\": \"2026-03-04 04:23:49.000000\"}'),(54,'Software migrations are a permanent, recurring problem driven by shifts in hardware economics, networking capability, and societal expectation — not failures of planning or engineering.','observation',49,NULL,'May need new topic: \'Software Architecture\' (top-level or child of a new \'Software Engineering\' parent)','2026-03-04 04:17:25','2026-03-04 04:42:44','{\"validity\": {\"consensus\": 5, \"soundness\": 5, \"factuality\": 5}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 5}, \"evaluated_at\": \"2026-03-04 04:23:49.000000\"}'),(55,'The core challenge of software migration is not the code itself but the lost rationale — design decisions, naming choices, and tradeoffs that lived outside the code in the heads of engineers who are no longer available.','mechanism',49,NULL,'May need new topic: \'Software Architecture\' (top-level or child of a new \'Software Engineering\' parent)','2026-03-04 04:17:25','2026-03-04 04:42:44','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 4, \"practicality\": 4}, \"evaluated_at\": \"2026-03-04 04:23:49.000000\"}'),(56,'Contemporary solutions architects in cloud environments are primarily making economic and systemic decisions — which services, messaging systems, and platforms to use — rather than structural software decisions.','observation',50,NULL,'May need new topic: \'Software Architecture\' (top-level or child of a new \'Software Engineering\' parent)','2026-03-04 04:17:25','2026-03-04 04:42:44','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 3, \"originality\": 3, \"practicality\": 4}, \"evaluated_at\": \"2026-03-04 04:23:49.000000\"}'),(57,'Companies like Amazon and Microsoft have codified common architectural patterns into reference documentation, reducing the need for most teams to rediscover solutions from first principles.','observation',50,NULL,'May need new topic: \'Software Architecture\' (top-level or child of a new \'Software Engineering\' parent)','2026-03-04 04:17:25','2026-03-04 04:23:49','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 5}, \"substance\": {\"impact\": 3, \"originality\": 3, \"practicality\": 4}, \"evaluated_at\": \"2026-03-04 04:23:49.000000\"}'),(58,'Software architecture is fundamentally about decisions — specifically the decisions that are most expensive to change.','definition',NULL,NULL,'May need new topic: \'Software Architecture\' (top-level or child of a new \'Software Engineering\' parent)','2026-03-04 04:17:35','2026-03-04 04:42:44','{\"validity\": {\"consensus\": 5, \"soundness\": 5, \"factuality\": 5}, \"substance\": {\"impact\": 4, \"originality\": 4, \"practicality\": 5}, \"evaluated_at\": \"2026-03-04 04:23:49.000000\"}'),(59,'UML was designed as a visual thinking and communication tool for reasoning about software systems, not as a code-generation language. The push to make it a programming language was a mistake that drove its decline.','assertion',NULL,NULL,'May need new topic: \'Software Architecture\' and/or \'Modeling Tools\' (top-level or child of new \'Software Engineering\' parent)','2026-03-04 04:17:35','2026-03-05 01:48:38','{\"validity\": {\"consensus\": 4, \"soundness\": 5, \"factuality\": 5}, \"substance\": {\"impact\": 3, \"originality\": 4, \"practicality\": 3}, \"evaluated_at\": \"2026-03-04 04:23:49.000000\"}'),(60,'The appropriate level of architectural formalism in a software project is determined by three axes: the degree of accountability and ceremony required, the cost of failure, and the novelty and complexity of the problem domain.','definition',NULL,NULL,'May need new topic: \'Software Architecture\' (top-level or child of a new \'Software Engineering\' parent)','2026-03-04 04:17:35','2026-03-04 04:23:49','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 4, \"practicality\": 5}, \"evaluated_at\": \"2026-03-04 04:23:49.000000\"}'),(61,'The collapse in computational cost means that for many categories of modern software, one can build, fail, and discard without the level of architectural investment that was once mandatory — AI accelerates this dynamic.','assertion',NULL,NULL,NULL,'2026-03-04 04:17:35','2026-03-05 01:48:38','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 4}, \"evaluated_at\": \"2026-03-04 04:23:49.000000\"}'),(62,'Software engineering will always require informed human decision-makers regardless of the abstraction level of available tools — the shift to AI-assisted development does not eliminate the need for judgment.','assertion',NULL,NULL,NULL,'2026-03-04 04:17:35','2026-03-05 01:48:38','{\"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 3, \"originality\": 2, \"practicality\": 4}, \"evaluated_at\": \"2026-03-04 04:23:49.000000\"}'),(63,'Object-oriented design\'s emphasis on inheritance over composition was a structural weakness that led to brittle abstractions — a lesson that influenced later shifts toward interfaces, composition, and dependency injection.','observation',NULL,NULL,'May need new topic: \'Software History\' or \'Object-Oriented Programming\' (child of new \'Software Engineering\' parent)','2026-03-04 04:17:35','2026-03-04 04:42:44','{\"validity\": {\"consensus\": 5, \"soundness\": 5, \"factuality\": 5}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 4}, \"evaluated_at\": \"2026-03-04 04:23:49.000000\"}'),(64,'The gap between individual AI productivity gains and organization-level results is an operating model failure, not a tool failure â€” the bottlenecks limiting value capture are organizational, not technical.','assertion',NULL,NULL,'Core thesis of McKinsey talk. Source 7 parent claim for productivity gap and role stagnation children.','2026-03-04 06:54:59','2026-03-05 01:48:38','{\"notes\": \"Well-supported by survey data and case studies. The interpretive framing (organizational vs. technical failure) is a logical inference from the data rather than a directly measured finding, but the reasoning is sound. Emerging consensus in practitioner literature.\", \"validity\": {\"consensus\": 3, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 4, \"practicality\": 4}}'),(65,'Unlocking the full value of AI in software development requires structural reorganization â€” new team sizes, roles, and workflows â€” not just layering AI tools onto existing agile structures.','assertion',NULL,NULL,'Core thesis: AI-native transformation analog to agile transformation. Parent for pod size, spec-driven, and task-model children.','2026-03-04 06:54:59','2026-03-05 01:48:38','{\"notes\": \"Core thesis of the source. Logically argued and supported by case study results, but ultimately prescriptive. The claim that structural change is required, not just beneficial, is asserted more than it is proven. Impact is high given the scope of organizational change implied.\", \"validity\": {\"consensus\": 3, \"soundness\": 4, \"factuality\": 3}, \"substance\": {\"impact\": 5, \"originality\": 4, \"practicality\": 4}}'),(66,'Top-performing enterprises achieve 5â€“6x improvements in delivery speed by restructuring around AI, producing results far beyond the 5â€“15% average reported across the broader enterprise population.','observation',NULL,NULL,'McKinsey survey, ~300 global enterprises. Parent for the 7x/6x role/workflow statistics.','2026-03-04 06:54:59','2026-03-04 07:04:43','{\"notes\": \"Direct survey finding from McKinsey. Factuality is credible as a reported figure. Soundness is limited by the lack of definition for top performer and undisclosed methodology. Selection bias in the top-performer cohort is a real risk. The 5-6x figure stands in notable contrast to the 5-15% average and the gap is not fully explained.\", \"validity\": {\"consensus\": 3, \"soundness\": 3, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 4}}'),(67,'Despite high individual-level AI productivity gains, McKinsey surveys of approximately 300 enterprises found companies reporting only 5â€“15% overall productivity improvement at the organization level.','observation',64,NULL,'McKinsey proprietary survey. Potential self-reporting and selection bias. Child of operating model failure claim.','2026-03-04 06:54:59','2026-03-04 07:04:43','{\"notes\": \"Direct survey finding from 300 enterprises. Self-reported productivity data carries inherent limitations, but the finding aligns with broader industry observations of underwhelming aggregate AI impact at enterprise scale. High consensus with other practitioner reports.\", \"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 3}}'),(68,'Approximately 70% of surveyed enterprises have not changed developer or PM roles at all, despite widespread AI tool adoption â€” role definition has not kept pace with capability change.','observation',64,NULL,'McKinsey survey finding. Child of operating model failure claim.','2026-03-04 06:54:59','2026-03-04 07:04:43','{\"notes\": \"Direct survey finding. The gap between tool adoption and role redefinition is a well-defined and concrete observation. Corroborated qualitatively by the change management case studies in the same source. Consensus is developing but not yet wide.\", \"validity\": {\"consensus\": 3, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 4}}'),(69,'Top-performing enterprises are 7x more likely to have AI-native workflows spanning four or more SDLC use cases, and 6x more likely to have AI-native roles with smaller, consolidated-skill pods.','observation',66,NULL,'McKinsey survey differentials. \"Top performer\" definition not fully disclosed â€” consulting-firm credibility risk. Child of top-performer differentiation claim.','2026-03-04 06:54:59','2026-03-04 07:04:43','{\"notes\": \"Direct survey finding. The 7x and 6x multipliers are striking and plausible but the absence of methodology detail limits confidence in soundness. Correlation vs. causation is unresolved. Top performers may have restructured because they were already high-capability organizations, not because restructuring caused the performance.\", \"validity\": {\"consensus\": 3, \"soundness\": 3, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 4}}'),(70,'AI-native teams replace traditional 8â€“10 person two-pizza teams with 3â€“5 person pods where engineers hold consolidated full-stack roles â€” \"product builders\" with agent orchestration skills rather than separate QA, frontend, and backend specialists.','assertion',65,NULL,'McKinsey role consolidation experiment. Child of structural change claim. Related to claim 39 (specialized agents) at the human team level.','2026-03-04 06:54:59','2026-03-05 01:48:38','{\"notes\": \"Specific and actionable structural prescription supported by two client experiments described in the source. Factuality is limited because these are consulting-client case studies without independent verification. The consolidation of QA, frontend, and backend into full-stack product builder roles is an emerging but not yet mainstream practice.\", \"validity\": {\"consensus\": 3, \"soundness\": 4, \"factuality\": 3}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 5}}'),(71,'AI-native development replaces story-driven development with spec-driven development and quarterly planning with continuous planning â€” PMs iterate on specs with agents rather than maintaining long PRDs, and prototype directly in code.','assertion',65,NULL,'McKinsey operating model framework. Child of structural change claim. Overlaps with claim 35 (spec-driven development), but focuses on the org-model transition rather than the technical governance pattern.','2026-03-04 06:54:59','2026-03-05 01:48:38','{\"notes\": \"Well-defined prescription grounded in observed AI-native startup practices including the Cursor case study referenced. The shift from story-driven to spec-driven development is a concrete and implementable change with clear rationale. Consensus is emerging among AI-native practitioners but not yet established enterprise practice.\", \"validity\": {\"consensus\": 3, \"soundness\": 4, \"factuality\": 3}, \"substance\": {\"impact\": 4, \"originality\": 4, \"practicality\": 5}}'),(72,'Different software engineering task types require different human-agent collaboration models: legacy modernization with well-defined outputs suits a factory-of-agents model, while greenfield and brownfield feature work benefits from an iterative co-creator loop with non-deterministic variation.','assertion',65,NULL,'McKinsey operating model segmentation. Presented as framework without supporting data on which conditions predict better performance â€” asserted, not demonstrated. Child of structural change claim.','2026-03-04 06:54:59','2026-03-05 01:48:38','{\"notes\": \"Sensible framework with intuitive logic. Legacy modernization and greenfield development do have different characteristics that would plausibly suit different collaboration models. However, this is presented as a framework assertion without supporting empirical data on which conditions predict which model performs better. Practical value is real but confidence in the specific categorization is moderate.\", \"validity\": {\"consensus\": 3, \"soundness\": 3, \"factuality\": 3}, \"substance\": {\"impact\": 3, \"originality\": 4, \"practicality\": 4}}'),(73,'Change management â€” not tooling â€” is the primary determinant of whether AI adoption produces outsized results; success requires getting 20â€“30 things right simultaneously, including communication, incentives, upskilling, and measurement.','assertion',NULL,NULL,'McKinsey change management framing. \"Getting a lot of small things right\" positions it as continuous operational discipline, not a single transformation initiative.','2026-03-04 06:54:59','2026-03-05 01:48:38','{\"notes\": \"Supported by the tech company change management case study, which provides a concrete before-and-after illustration. The 20-30 things simultaneously framing is experiential and not formally defined, but the directional claim that change management dominates tooling as a predictor of outcome is logically consistent with the survey findings and case studies.\", \"validity\": {\"consensus\": 3, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 4}}'),(74,'The absence of measurement is itself a failure mode in AI adoption â€” bottom-performing enterprises were not measuring delivery speed, and only 10% were measuring productivity at all.','observation',NULL,NULL,'McKinsey survey finding on measurement gaps.','2026-03-04 06:54:59','2026-03-04 07:04:43','{\"notes\": \"Direct survey finding with high face validity. The observation that bottom performers were not measuring basic outcomes (speed, productivity) is both specific and practically significant. Consensus is high and aligns with widespread practitioner experience that organizations cannot improve what they do not measure.\", \"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 5}}'),(75,'A rigorous AI productivity measurement framework must cover inputs (tool investment, upskilling resources), direct outputs (velocity, adoption), quality outputs (developer NPS, code security, resilience), and economic outcomes (time to revenue, cost per pod) â€” proxy metrics alone are insufficient.','definition',NULL,NULL,'McKinsey MECE measurement model. Speakers acknowledge it is still maturing as tools evolve.','2026-03-04 06:54:59','2026-03-04 07:04:43','{\"notes\": \"MECE-structured framework with clear logical organization from inputs through outputs to economic outcomes. The framework is comprehensive and actionable. Factuality is limited because this is a proposed framework rather than a validated measurement model. The speakers acknowledge it is a starting point and that proxies will evolve. High practical value for organizations currently measuring nothing or measuring only adoption.\", \"validity\": {\"consensus\": 3, \"soundness\": 4, \"factuality\": 3}, \"substance\": {\"impact\": 4, \"originality\": 4, \"practicality\": 5}}'),(76,'AI-accelerated code generation amplifies technical debt and codebase complexity, creating new bottlenecks that partially offset the productivity gains it enables.','assertion',NULL,NULL,'Referenced Carnegie Mellon research (no full citation provided in talk). Brief mention â€” independent verification difficult.','2026-03-04 06:54:59','2026-03-05 01:48:38','{\"notes\": \"Supported by a Carnegie Mellon research report citation that is external to this source. The mechanism is well-reasoned: AI generates more code faster, but code review and architecture governance have not scaled proportionally, leading to accumulated technical debt and complexity. This finding has strong alignment with practitioner observations and is gaining consensus. The absence of CMU citation detail in the talk limits independent verification.\", \"validity\": {\"consensus\": 4, \"soundness\": 4, \"factuality\": 4}, \"substance\": {\"impact\": 4, \"originality\": 3, \"practicality\": 3}}');
