INSERT INTO `contributors` VALUES (1,'Yegor Denisov-Blanch','Denisov-Blanch, Yegor','Stanford University','Researcher','Yegor Denisov-Blanch is a researcher with the Stanford Software Engineering Productivity Research Group, where he studies how AI is changing software development. His research analyzes data from hundreds of organizations and over 50,000 engineers to quantify the real-world impact of AI on engineering teams. His work has been featured at the United Nations and in the Washington Post, and has been used to inform World Bank guidance on AI labor impacts.','https://aiconference.com/wp-content/uploads/2025/08/Yegor-Denisov-Blanch-1.jpg','https://www.yegordb.com','2026-03-01 19:24:30','{\"tier\": 2, \"reach\": 4, \"authority\": 3, \"expertise\": 3, \"reputation\": 3, \"evaluated_at\": \"2026-03-02 16:28:02.000000\"}'),(2,'Martin Fowler','Fowler, Martin','Thoughtworks','Chief Data Scientst','Chief Scientist at Thoughtworks. Author of Refactoring and Patterns of Enterprise Application Architecture. Pioneer of agile software development and co-author of the Agile Manifesto. Specializes in object-oriented analysis, UML, patterns, and agile methodologies.','https://martinfowler.com/mf.jpg','https://martinfowler.com','2026-03-01 21:49:55','{\"tier\": 1, \"reach\": 5, \"authority\": 5, \"expertise\": 5, \"reputation\": 5, \"reach_notes\": \"Prolific blogger with massive global readership; ThoughtWorks platform amplifies reach significantly.\", \"evaluated_at\": \"2026-03-02 16:28:02.000000\", \"authority_notes\": \"Regular keynote speaker at major conferences; books are standard references in the field.\", \"expertise_notes\": \"Created foundational software architecture patterns adopted industry-wide; authored multiple definitive texts.\", \"reputation_notes\": \"Decades-long track record of prescient recommendations; peers consistently defer to his judgment.\"}'),(3,'Korny Sietsma','Sietsma, Korny','Liberis','Author','Korny Sietsma (Kornelis Sietsma) is a software engineer and engineering lead with over 19 years of experience, currently working as a Principal Engineer at John Lewis Partnership after several years at Liberis. He spent 12 years at Thoughtworks before moving into product engineering roles. His expertise spans agile practices, software architecture, code visualisation, and agentic AI security.','https://avatars.githubusercontent.com/u/17765?v=4','https://blog.korny.info','2026-03-01 23:52:11','{\"tier\": 3, \"reach\": 2, \"authority\": 2, \"expertise\": 3, \"reputation\": 3, \"evaluated_at\": \"2026-03-02 16:28:02.000000\"}'),(4,'Daniel Sheard','Sheard, Daniel','QuantumBlack, AI by McKinsey','Distinguished Engineer','Daniel Sheard is a Distinguished Engineer at QuantumBlack, AI by McKinsey, based in London. He focuses on agentic AI systems and software engineering patterns, and is pursuing part-time doctoral research at the University of Oxford. He co-authors technical thought leadership for QuantumBlack on building production-grade agentic workflows.',NULL,'https://www.linkedin.com/in/danielsheard','2026-03-02 00:26:41','{\"tier\": 2, \"reach\": 2, \"authority\": 3, \"expertise\": 4, \"reputation\": 3, \"evaluated_at\": \"2026-03-02 16:28:02.000000\"}'),(5,'Jo Stichbury','Stichbury, Jo','QuantumBlack, AI by McKinsey','Technical Editor','Jo Stichbury is a Technical Editor and writer at QuantumBlack, AI by McKinsey, specializing in data science, machine learning, and AI. She is based in London and educated at the University of Cambridge. She has contributed to open-source projects including Kedro and Vizro, and writes and edits technical thought leadership for QuantumBlack.','https://github.com/stichbury.png','https://github.com/stichbury','2026-03-02 00:26:41','{\"tier\": 2, \"reach\": 3, \"authority\": 3, \"expertise\": 3, \"reputation\": 3, \"evaluated_at\": \"2026-03-02 16:28:02.000000\"}'),(6,'Gergely Orosz','Orosz, Gergely','The Pragmatic Engineer','Writer, Software Engineer','Gergely Orosz is the writer and founder of The Pragmatic Engineer, the #1 technology newsletter on Substack covering engineering and engineering management. He previously worked as a software engineer and engineering manager at Uber, Microsoft/Skype, and Skyscanner. He is the author of The Software Engineer\'s Guidebook (2023).','https://avatars.githubusercontent.com/u/1094502?v=4','https://blog.pragmaticengineer.com','2026-03-04 04:10:42','{\"tier\": 1, \"reach\": 4, \"authority\": 4, \"expertise\": 4, \"reputation\": 4, \"evaluated_at\": \"2026-03-04 04:10:42.000000\"}'),(7,'Grady Booch','Booch, Grady','IBM Research','IBM Fellow, Chief Scientist','Grady Booch is an IBM Fellow and Chief Scientist for Software Engineering at IBM Research, widely recognized as a pioneer in object-oriented analysis and design and a co-creator of the Unified Modeling Language (UML). He developed the Booch method of software development and co-founded Rational Software Corporation in 1981, which IBM acquired in 2003. He is a Fellow of the ACM and IEEE, a recipient of the Lovelace Medal, and the author of six books on software engineering and architecture.','https://avatars.githubusercontent.com/u/7682013?v=4','https://www.gradybooch.com','2026-03-04 04:10:42','{\"tier\": 1, \"reach\": 4, \"authority\": 5, \"expertise\": 5, \"reputation\": 5, \"evaluated_at\": \"2026-03-04 04:10:42.000000\"}'),(8,'Martin Harrysson','Harrysson, Martin','McKinsey & Company','Partner','Martin Harrysson is a Senior Partner at McKinsey & Company in the Bay Area, where he leads the firm’s Software X practice focused on AI-native software development. He holds a BS in Computer Science and Engineering from MIT and advises high-tech, software, and financial services companies on operating model transformation, product development, and scaling AI capabilities across engineering organizations.','https://static.licdn.com/aero-v1/sc/h/bgaqk7x4ntjz0wg67d8u723eb','https://www.mckinsey.com/our-people/martin-harrysson','2026-03-04 06:47:45','{\"tier\": 1, \"reach\": 3, \"authority\": 4, \"expertise\": 4, \"reputation\": 4, \"evaluated_at\": \"2026-03-04 06:50:46.000000\"}'),(9,'Natasha Maniar','Maniar, Natasha','McKinsey & Company','Partner','Natasha Maniar is an Associate Partner at McKinsey & Company who works on AI-native software development and organizational transformation alongside Senior Partner Martin Harrysson. She previously developed multimodal AI applications and holds an affiliation with MIT Media Lab. Her research focuses on how enterprises can move beyond marginal productivity gains to systemic AI-native workflows and measurement frameworks.',NULL,'https://www.linkedin.com/in/natasha-maniar-945276107','2026-03-04 06:47:45','{\"tier\": 2, \"reach\": 2, \"authority\": 3, \"expertise\": 4, \"reputation\": 3, \"evaluated_at\": \"2026-03-04 06:50:46.000000\"}');
