INSERT INTO `curation_rule_versions` VALUES (1,1,1,'**Include** content where AI is a tool engineers use to build software such as code generation, testing, code review, debugging, development practices, and team workflows.\n\n**Exclude** content where AI is the product being built such as models in production, AI-powered features shipped to end users, model training, and MLOps.',NULL,'2026-03-03 23:16:44'),(2,1,2,'**Include** content where AI is a tool engineers use to build software such as code generation, testing, code review, debugging, development practices, and team workflows.\n\n**Exclude** content where AI is the product being built such as models in production, AI-powered features shipped to end users, model training, and MLOps.\n\nTest',NULL,'2026-03-03 23:34:39'),(3,1,3,'**Include** content where AI is a tool engineers use to build software such as code generation, testing, code review, debugging, development practices, and team workflows.\n\n**Exclude** content where AI is the product being built such as models in production, AI-powered features shipped to end users, model training, and MLOps.',NULL,'2026-03-03 23:36:18'),(4,1,4,'**Include** content where AI is a tool engineers use to build software such as code generation, testing, code review, debugging, development practices, and team workflows.\n\n\n**Exclude** content where AI is the product being built such as models in production, AI-powered features shipped to end users, model training, and MLOps.\n\n\nStay as vendor-agnostic as possible. Specific AI tools or models may be named when the source material references them directly or when a comparison is meaningful, but focus on engineering practices, not specific tools.\n\nAvoid technical step-by-step instructions. Do not describe UI interactions, installation steps, or menu navigation. Focus on concepts, mechanisms, and decisions — the why and what, not the click-by-click how.',NULL,'2026-03-04 21:44:20');
/*!40000 ALTER TABLE `curation_rule_versions` ENABLE KEYS */;
UNLOCK TABLES;

