INSERT INTO `curation_rules` VALUES (1,'AI as an Engineering Tool','Includes content where AI is a tool engineers use to build software. Excludes content where AI is the product being built. Stay as vendor-agnostic. Avoid technical step-by-step instructions.',1,'2026-03-03 23:16:44','2026-03-04 21:41:45');
/*!40000 ALTER TABLE `curation_rules` ENABLE KEYS */;
UNLOCK TABLES;

