LOCK TABLES `devices` WRITE;
/*!40000 ALTER TABLE `devices` DISABLE KEYS */;
INSERT INTO `devices` VALUES (1,'The complexity-by-maturity matrix â€” a 2x2 grid crossing task complexity (low/high) with codebase maturity (greenfield/brownfield) â€” showing productivity gains ranging from 30â€“40% down to 0â€“10% depending on quadrant.',2,'visual','Makes the abstract interaction of two variables concrete and memorable; the dramatic range across quadrants is immediately striking.',NULL,'2026-03-03 04:00:18'),(2,'The \"ghost engineer\" finding â€” roughly 10% of ~50,000 engineers studied contributed essentially no meaningful output while drawing full compensation.',2,'narrative','Attention-grabbing finding that anchors the credibility of the measurement methodology; tangential to AI but validates the research apparatus.',NULL,'2026-03-03 04:00:18'),(3,'The rework decomposition â€” categorizing all code changes into added functionality, removed code, refactoring, and rework â€” to distinguish gross from net productivity.',2,'example','Concretely demonstrates why raw output metrics are misleading; the four-category breakdown is intuitive and memorable.',NULL,'2026-03-03 04:00:18'),(4,'Developer self-assessment validation â€” 43 developers estimated their productivity in percentile buckets, revealing near-random correlation with measured output, with 30-percentile-point errors.',2,'example','Viscerally undermines confidence in self-reported productivity surveys, which many competing studies rely on.',NULL,'2026-03-03 04:00:18'),(5,'The dot-com bubble analogy â€” canals, railroads, and the internet all followed bubble-and-burst cycles; Pets.com and Webvan died but Amazon survived, demonstrating that real value survives even when speculative excess collapses.',3,'analogy','Immediately grounds the AI bubble claim in familiar history; the Amazon survival example gives practitioners a framework for evaluating which AI investments might endure.',NULL,'2026-03-03 04:00:58'),(6,'Rebecca Parsons\' reframing: \"All LLM output is hallucination; the useful outputs are simply hallucinations that happen to be correct.\" This inverts the conventional framing from defect-to-fix to feature-to-manage.',3,'metaphor','Conceptually powerful â€” shifts the entire conversation from \"how do we eliminate hallucinations\" to \"how do we build workflows that account for them.\"',NULL,'2026-03-03 04:00:58'),(7,'LLMs as the moment software engineering joins other engineering disciplines in confronting non-determinism â€” structural and process engineers have always dealt with variability and tolerance requirements that software engineers have not.',3,'analogy','Normalizes LLM unpredictability by placing it in a broader engineering tradition rather than treating it as uniquely problematic.',NULL,'2026-03-03 04:00:58'),(8,'The white-on-white text attack â€” an attacker embeds instructions in 1pt white text on a web page, invisible to humans but readable by the LLM, to manipulate a browser-based agent into exfiltrating banking data.',3,'example','Vivid, concrete attack scenario that makes the abstract \"prompt injection\" threat immediately tangible and alarming.',NULL,'2026-03-03 04:00:58'),(9,'The \"Lethal Trifecta\" â€” Simon Willison\'s three-condition model where the simultaneous presence of sensitive data access, untrusted content exposure, and external communication capability creates a fundamentally unsafe agent architecture.',4,'metaphor','The dramatic name makes the abstract security model memorable and quotable; the three-leg structure provides a clear mental framework for risk assessment.',NULL,'2026-03-03 04:01:45'),(10,'The AgentFlayer attack â€” a user queries Jira tickets via MCP, a Zendesk-sourced attacker-crafted ticket instructs the LLM to find JWT tokens (identifiable by the \"eyj\" prefix) and post them as a public Jira comment, exploiting all three trifecta legs.',4,'example','Concrete end-to-end attack chain using real-world tools (Jira, Zendesk, MCP) makes the abstract threat viscerally real for practitioners.',NULL,'2026-03-03 04:01:45'),(11,'Data exfiltration via image URL â€” a GET request to an attacker server disguised as an image load (foo.png?var=[stolen_data]) silently transmits data, showing that any internet access is an exfiltration channel.',4,'example','Elegantly demonstrates that exfiltration vectors are broader than most developers assume; the image-load disguise is particularly surprising.',NULL,'2026-03-03 04:01:45'),(12,'The \"Head Chef\" framing from Gene Kim and Steve Yegge â€” when the customer sends back the fish because the sauce is broken, you can\'t blame your sous chef. Developers using LLM agents remain fully responsible for all outputs.',4,'analogy','Immediately relatable professional responsibility metaphor that cuts through the temptation to blame the tool.',NULL,'2026-03-03 04:01:45'),(13,'The microservices analogy for specialized agents â€” a network of focused, single-responsibility agents trades one complex system for multiple simpler systems plus the orchestration cost of managing interfaces between them, just as microservices trade monolith complexity for distributed system complexity.',5,'analogy','Leverages a concept most software engineers already understand deeply; immediately communicates both the benefit and the cost of the agent specialization pattern.',NULL,'2026-03-03 04:02:35'),(14,'Self-orchestrating agent failure modes â€” agents given meta-level control routinely skipped steps, created circular dependencies, and entered analysis loops on larger codebases.',5,'example','Concrete failure catalog that makes the abstract argument for deterministic orchestration vivid; each failure mode is immediately recognizable to practitioners.',NULL,'2026-03-03 04:02:35'),(15,'The knowledge agent notification query â€” \"Should notifications be sent synchronously or via a queue?\" with the logged assumption \"Using async queue-based delivery (not synchronous)\" appearing as a discrete, structured item in the pull request diff.',5,'example','Transforms the abstract concept of \"institutional memory\" into a concrete, reviewable artifact that developers can immediately picture in their workflow.',NULL,'2026-03-03 04:02:35'),(16,'Folder and naming conventions as dual-purpose infrastructure â€” organizing artifacts for human developers AND making the system machine-readable for the workflow engine, collapsing human and machine legibility into a single convention.',5,'thought_experiment','Reframes what developers see as mundane convention into a key architectural decision; the \"dual-purpose\" insight is non-obvious and memorable.',NULL,'2026-03-03 04:02:35'),(17,'Booch\'s quote \"Migrations will plague us until the heat death of the cosmos\" uses cosmic-scale hyperbole to drive home that software migration is not a temporary problem waiting for a technological solution â€” it is a permanent feature of the discipline.',6,'metaphor','Highly quotable; the absurdist scale makes the claim memorable and rhetorically forceful.',NULL,'2026-03-04 04:19:39'),(18,'The IRS IBM 360 Assembly Language running on \"emulators stacked on emulators\" is a narrative image of escalating archaeological layers of technology â€” each emulator a memorial to a hardware era that ended but whose obligations did not.',6,'narrative','Vivid layering image that makes legacy debt tangible without needing statistics.',NULL,'2026-03-04 04:19:39'),(19,'The personal desktop cluster of four Nvidia single-board computers carrying more compute than all 1970s hardware combined is an analogy that translates abstract cost-collapse arguments into a physical, holdable object.',6,'analogy','Makes the compute cost collapse viscerally concrete â€” effective for a general audience.',NULL,'2026-03-04 04:19:39'),(20,'The three-axis formalism model (ceremony Ã— risk Ã— complexity) is a visual/conceptual framework that maps the question \"do I need UML?\" onto a three-dimensional space, making the decision systematic rather than tribal.',6,'thought_experiment','Converts a cultural debate into a structured decision framework â€” useful for practitioners and book readers alike.',NULL,'2026-03-04 04:19:39'),(21,'Booch\'s description of Linus Torvalds as the source of \"conceptual integrity\" for the Linux kernel, and his prediction of post-Torvalds drift, is an example that makes the abstract concept of architectural coherence dependent on human judgment concrete.',6,'example','Real, named, current example â€” readers can verify and relate to it.',NULL,'2026-03-04 04:19:39'),(22,'The shift from waterfall to agile is used as the historical template for the shift to AI-native development â€” both required structural reorganization of teams, roles, and ceremonies rather than just adopting new practices on top of existing structures. Drawn from the speaker\'s personal engineering experience during the agile transition approximately 20 years ago.',7,'analogy',NULL,'Core framing device for the structural change argument. Rhetorical, not empirical.','2026-03-04 07:00:14'),(23,'AI adoption failure is presented as two distinct failure modes â€” point adoption without workflow change, and workflow change without structural role change â€” creating a diagnostic framework that positions the operating model as the root cause rather than the tools.',7,'analogy',NULL,'Analytical diagnostic frame. Positions marginal gains as predictable outcomes of structural incompleteness.','2026-03-04 07:00:14'),(24,'The McKinsey MECE (mutually exclusive, collectively exhaustive) framework is applied to AI productivity measurement, organizing inputs, outputs, quality outputs, and economic outcomes into a structured, non-overlapping taxonomy that makes measurement gaps visible.',7,'analogy',NULL,'McKinsey-standard consulting framework repurposed as a measurement design tool.','2026-03-04 07:00:14'),(25,'Two distinct human-agent collaboration models are presented as a segmentation by task type â€” factory-of-agents for structured legacy modernization, iterative co-creator loop for exploratory new feature development â€” creating a decision framework for practitioners.',7,'analogy',NULL,'Segmentation framework presented without empirical validation. Useful as a thinking tool but asserted rather than demonstrated.','2026-03-04 07:00:14');
/*!40000 ALTER TABLE `devices` ENABLE KEYS */;
