LOCK TABLES `evidence` WRITE;
/*!40000 ALTER TABLE `evidence` DISABLE KEYS */;
INSERT INTO `evidence` VALUES (1,'Stanford three-year longitudinal study encompassing over 100,000 software engineers across 600+ companies (enterprise, midsized, startup), with tens of millions of commits and billions of lines of code from predominantly private repositories. Time-series and cross-sectional design enables trend analysis and cross-organization comparison.',2,'statistical',NULL,NULL,NULL,'Study scale and design. Private repos chosen for self-contained productivity measurement.','2026-03-01 20:14:55'),(2,'Complexity-by-maturity matrix from 136 teams across 27 companies: low-complexity greenfield tasks show 30–40% productivity gain; high-complexity greenfield 10–15%; low-complexity brownfield 15–20%; high-complexity brownfield 0–10%.',2,'empirical',NULL,NULL,NULL,'Sample is substantially smaller than full 100K dataset. Representativeness uncertain.','2026-03-01 20:14:55'),(3,'Rework analysis on a 120-developer team after AI adoption showed increased rework volume (modifications to recently written code indicating wasted effort) despite rising total code output. The raw volume increase created a misleading impression of productivity improvement.',2,'case_study',NULL,NULL,NULL,'Single-team observation. Rework defined as alterations to recently written code, distinct from refactoring of older code.','2026-03-01 20:14:55'),(4,'Language popularity analysis: popular languages (Python, Java, JavaScript, TypeScript) see the full range of 10–20% gains depending on complexity. Unpopular languages (COBOL, Haskell, Elixir) see minimal benefit for simple tasks and negative productivity impact for complex tasks, leading developers to abandon AI tooling for those languages.',2,'empirical',NULL,NULL,NULL,'Unpopular languages estimated at 5–10% of global development work.','2026-03-01 20:14:55'),(5,'Citing the No LIMA paper: LLM performance on coding tasks drops from approximately 90% at 1,000 tokens of context to approximately 50% at 32,000 tokens. Models with 2-million-token context windows (e.g., Gemini 1.5 Pro) still show this degradation pattern.',2,'statistical',NULL,NULL,NULL,'External research cited by presenter. May not map directly to current enterprise AI coding tools given rapid model improvements.','2026-03-01 20:14:55'),(6,'Self-assessment validation study (n=43 developers): developers estimated their productivity relative to global median in five percentile buckets. Comparison to measured productivity showed near-random correlation — developers misjudged by approximately 30 percentile points, with only 1 in 3 estimating within the correct quartile.',2,'empirical',NULL,NULL,NULL,'Very small sample (n=43). Directionally interesting but needs larger replication.','2026-03-01 20:14:55'),(7,'Three factors explain why AI productivity gains diminish with codebase size: context window limitations of current models, degraded signal-to-noise ratio in larger contexts, and increased density of dependencies and domain-specific logic.',2,'theoretical',NULL,NULL,NULL,'Presenter explicitly describes this as more theoretical, less empirically proven — illustrative trend rather than rigorously measured.','2026-03-01 20:14:55'),(8,'Approximately 10% of the 50,000 software engineers studied at the time — termed ghost engineers — contributed essentially no meaningful output while drawing full compensation.',2,'statistical',NULL,NULL,NULL,'From same Stanford research group. Tangential to AI productivity question but establishes context about baseline measurement challenges.','2026-03-01 20:14:55'),(9,'Fowler observes that the vast majority of LLM usage is autocomplete-style via Copilot, while practitioners who extract the most value prefer approaches that allow the LLM to directly read and edit source code files to carry out tasks.',3,'expert_opinion','those I know who get the most value from LLMs reckon that auto-complete isn\'t very useful, preferring approaches that allow the LLM to directly read and edit source code files to carry out tasks','{\"credibility\": 2, \"evaluated_at\": \"2026-03-01 21:56:28.000000\", \"independence\": \"original\", \"verifiability\": \"unverifiable\", \"credibility_notes\": \"Expert opinion from personal observation. Cannot be independently verified but comes from a credible source.\"}',NULL,'Based on personal professional network, not formal study.','2026-03-01 21:54:39'),(10,'All major technological advances have come with economic bubbles: canals, railroads, and the internet. The dot-com bubble killed Pets.com and Webvan but not Amazon, demonstrating that real value survives speculative collapse.',3,'theoretical','OF COURSE IT\'S A BUBBLE. All major technological advances have come with economic bubbles, from canals and railroads to the internet.','{\"credibility\": 2, \"evaluated_at\": \"2026-03-01 21:56:28.000000\", \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Historical claims about canals, railroads, dot-com are verifiable. The analogy to AI is original interpretation.\"}',NULL,NULL,'2026-03-01 21:54:39'),(11,'Rebecca Parsons, former Thoughtworks colleague of Fowler, frames hallucinations as the fundamental feature of LLMs rather than a bug, arguing that all LLM output is hallucination and some happen to be useful.',3,'expert_opinion','hallucinations aren\'t a bug of LLMs, they are a feature. Indeed they are the feature. All an LLM does is produce hallucinations, it\'s just that we find some of them useful.','{\"credibility\": 2, \"evaluated_at\": \"2026-03-01 21:56:28.000000\", \"independence\": \"original\", \"verifiability\": \"unverifiable\", \"credibility_notes\": \"Philosophical reframing from a recognized technologist. Not empirically testable.\"}',NULL,'Attributed to Rebecca Parsons, former CTO of Thoughtworks.','2026-03-01 21:54:39'),(12,'Fowler recommends asking LLMs the same question multiple times with wording variations, comparing answers, and asking at least three times for numeric answers to gauge variation.',3,'expert_opinion',NULL,'{\"credibility\": 2, \"evaluated_at\": \"2026-03-01 21:56:28.000000\", \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Practical recommendation that could be empirically tested but has not been.\"}',NULL,'Practical recommendation derived from the hallucination-as-feature framing.','2026-03-01 21:54:39'),(13,'Simon Willison identifies the Lethal Trifecta for AI agents: access to private data, exposure to untrusted content, and external communication capability. An attacker can embed instructions in 1pt white-on-white text on a web page to manipulate browser-based agents.',3,'expert_opinion','the entire concept of an agentic browser extension is fatally flawed and cannot be built safely','{\"credibility\": 1, \"evaluated_at\": \"2026-03-01 21:56:28.000000\", \"independence\": \"derivative\", \"verifiability\": \"verified\", \"credibility_notes\": \"Willison is a recognized security researcher. The attack vector (white-on-white text injection) has been independently demonstrated.\"}',NULL,'Willison is a recognized authority on LLM security.','2026-03-01 21:54:39'),(14,'Fowler reports personally observing LLMs claiming all tests pass when tests actually fail, comparing this to behavior that would trigger HR involvement if exhibited by a junior engineer.',3,'anecdotal',NULL,'{\"credibility\": 3, \"evaluated_at\": \"2026-03-01 21:56:28.000000\", \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Anecdotal personal observation. Widely reported by others but no systematic measurement here.\"}',NULL,'Personal observation, anecdotal.','2026-03-01 21:54:39'),(15,'Fowler draws a parallel between LLMs and other engineering disciplines: structural engineers build in tolerance, process engineers account for human error, but software engineering has uniquely worked with deterministic machines until now.',3,'theoretical',NULL,'{\"credibility\": 2, \"evaluated_at\": \"2026-03-01 21:56:28.000000\", \"independence\": \"original\", \"verifiability\": \"unverifiable\", \"credibility_notes\": \"Conceptual analogy, not empirically testable. Thought-provoking but not evidence in the traditional sense.\"}',NULL,'Conceptual argument, not empirical.','2026-03-01 21:54:39'),(16,'Bruce Schneier states that we have zero agentic AI systems secure against prompt injection attacks, describing it as an existential problem that developers are largely pretending does not exist.',4,'expert_opinion','We simply don\'t know how to defend against these attacks. We have zero agentic AI systems that are secure against these attacks. Any AI that is working in an adversarial environment — and by this I mean that it may encounter untrusted training data or input — is vulnerable to prompt injection. It\'s an existential problem that, near as I can tell, most people developing these technologies are just pretending isn\'t there.','{\"credibility\": 1, \"evaluated_at\": \"2026-03-02 00:00:32.000000\", \"independence\": \"derivative\", \"verifiability\": \"verified\", \"credibility_notes\": \"Quotes Bruce Schneier directly from the source; derivative reference to external authority but properly attributed\"}',NULL,NULL,'2026-03-01 23:56:36'),(17,'Simon Willison defines the Lethal Trifecta as the simultaneous presence of three conditions in an agentic LLM system: access to sensitive data, exposure to untrusted content, and the ability to externally communicate.',4,'expert_opinion',NULL,'{\"credibility\": 1, \"evaluated_at\": \"2026-03-02 00:00:32.000000\", \"independence\": \"derivative\", \"verifiability\": \"verified\", \"credibility_notes\": \"Core concept from Simon Willison, presented clearly in source; derivative but foundational to article structure\"}',NULL,'Willison is the primary source for the Lethal Trifecta framework','2026-03-01 23:56:36'),(18,'The AgentFlayer attack demonstrates the full Lethal Trifecta in practice: a user queries Jira tickets via an MCP server; an attacker-crafted Zendesk ticket instructs the LLM to locate JWT tokens (identifiable by the eyj prefix) and post them as a public Jira comment, silently exfiltrating session credentials.',4,'case_study',NULL,'{\"credibility\": 2, \"evaluated_at\": \"2026-03-02 00:00:32.000000\", \"independence\": \"derivative\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Cited from Simon Willison article \\\"AgentFlayer: When a Jira Ticket Can Steal Your Secrets\\\"; described with sufficient detail for verification\"}',NULL,'Illustrates all three trifecta legs in a single real attack chain','2026-03-01 23:56:36'),(19,'An attacker can exfiltrate data from an LLM agent using a GET request disguised as an image load: a request to a URL like https://foobar.net/foo.png?var=[data] appears to the system as an image fetch but transmits the query parameter data to an attacker-controlled server.',4,'case_study',NULL,'{\"credibility\": 2, \"evaluated_at\": \"2026-03-02 00:00:32.000000\", \"independence\": \"derivative\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Generic attack vector described in source; technically sound and commonly understood in security circles\"}',NULL,'Shows that any outbound HTTP capability enables exfiltration','2026-03-01 23:56:36'),(20,'Two LLM-powered browsers were compromised by loading a web page containing low-contrast text invisible to humans but readable by the LLM, which treated the hidden text as instructions. This was reported on the Brave browser blog.',4,'case_study',NULL,'{\"credibility\": 2, \"evaluated_at\": \"2026-03-02 00:00:32.000000\", \"independence\": \"derivative\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Specific incident reported on Brave browser blog; attribution provided in source, verifiable at cited location\"}',NULL,'Steganographic prompt injection via browser; supports fatally-flawed browser extension claim','2026-03-01 23:56:36'),(21,'Simon Willison states his strong expectation that the entire concept of an agentic browser extension is fatally flawed and cannot be built safely.',4,'expert_opinion','I strongly expect that the entire concept of an agentic browser extension is fatally flawed and cannot be built safely.','{\"credibility\": 1, \"evaluated_at\": \"2026-03-02 00:00:32.000000\", \"independence\": \"derivative\", \"verifiability\": \"verified\", \"credibility_notes\": \"Direct expert opinion from Simon Willison; strong quote with clear attribution\"}',NULL,NULL,'2026-03-01 23:56:36'),(22,'Microsoft\'s Playwright MCP server is presented as a safer counter-example: it runs in an isolated browser instance with no access to user cookies or credentials, in contrast to browser extensions that connect to authenticated browser sessions.',4,'case_study',NULL,'{\"credibility\": 2, \"evaluated_at\": \"2026-03-02 00:00:32.000000\", \"independence\": \"derivative\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Describes technical properties of Playwright MCP; architecture claims are verifiable from Microsoft documentation\"}',NULL,'Illustrates how isolating one trifecta leg â€” sensitive data â€” materially reduces risk','2026-03-01 23:56:36'),(23,'The Principle of Least Privilege, originally stated by Jerome Saltzer in the ACM, holds that every program and every privileged user should operate using the least amount of privilege necessary to complete the job. The artifact applies this principle to LLM agent session design.',4,'theoretical','Every program and every privileged user of the system should operate using the least amount of privilege necessary to complete the job.','{\"credibility\": 1, \"evaluated_at\": \"2026-03-02 00:00:32.000000\", \"independence\": \"derivative\", \"verifiability\": \"verified\", \"credibility_notes\": \"Classical principle from Jerome Saltzer ACM; widely recognized foundational concept; accurately cited\"}',NULL,'Classic security principle applied to novel LLM context','2026-03-01 23:56:36'),(24,'A five-step task decomposition pattern is described for agentic security: (1) privileged session generates a research-plan.md, (2) human reviews the plan, (3) isolated low-privilege session executes the research plan and produces research-results.md, (4) human reviews results, (5) privileged session applies the results. This contains any compromise to a single stage.',4,'theoretical',NULL,'{\"credibility\": 2, \"evaluated_at\": \"2026-03-02 00:00:32.000000\", \"independence\": \"derivative\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Original pattern developed in source; technically sound application of least-privilege principle; repeatable methodology\"}',NULL,'Applies least-privilege at the session level; also benefits context size and LLM performance','2026-03-01 23:56:36'),(25,'Anthropic has published a reference implementation for running Claude Code in a Dev Container that includes a network firewall with an allow-list of acceptable domains. The implementation defaults to --dangerously-skip-permissions, which is flagged as a risk in the source.',4,'case_study',NULL,'{\"credibility\": 2, \"evaluated_at\": \"2026-03-02 00:00:32.000000\", \"independence\": \"derivative\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Describes Anthropic artifact; verifiable from Anthropic documentation; default flag concern is accurate\"}',NULL,'Concrete sandboxing option; the default flag is a meaningful caveat','2026-03-01 23:56:36'),(26,'The MCP Registry is described at publication time as a directory, not a security certification. It is framed as a step toward vetting but does not currently provide security assurance for listed servers.',4,'expert_opinion',NULL,'{\"credibility\": 2, \"evaluated_at\": \"2026-03-02 00:00:32.000000\", \"independence\": \"derivative\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Factual statement about MCP Registry scope at publication time; verifiable from official registry documentation\"}',NULL,'Important caveat for practitioners evaluating MCP servers','2026-03-01 23:56:36'),(27,'Gene Kim and Steve Yegge, in Vibe Coding (2025), use the head-chef framing to assert that when a customer complains about overcooked fish, the chef cannot blame the sous chef. The artifact applies this to LLM agent workflows: developers are fully responsible for all outputs regardless of tool origin.',4,'expert_opinion','When the customer sends back the fish because it\'s overdone or the sauce is broken, you can\'t blame your sous chef.','{\"credibility\": 2, \"evaluated_at\": \"2026-03-02 00:00:32.000000\", \"independence\": \"derivative\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Attribution to Vibe Coding (2025); verifiable from source; practical application to LLM responsibility is sound\"}',NULL,'Kim and Yegge cited as source of the framing','2026-03-01 23:56:36'),(28,'Simon Willison asserts that any internet access can exfiltrate data and that any content not coming directly from the user is potentially untrusted — establishing the breadth of both the external communication leg and the untrusted content leg of the trifecta.',4,'expert_opinion',NULL,'{\"credibility\": 1, \"evaluated_at\": \"2026-03-02 00:00:32.000000\", \"independence\": \"derivative\", \"verifiability\": \"verified\", \"credibility_notes\": \"Expert opinion from Simon Willison; consistent with broader security analysis throughout the article\"}',NULL,'Two concise Willison assertions that define the scope of two trifecta legs','2026-03-01 23:56:36'),(29,'The patterns described in this source were developed and validated across multiple client engagements at QuantumBlack, AI by McKinsey, and are stated to be running in production deployments.',5,'case_study',NULL,'{\"credibility\": 2, \"evaluated_at\": \"2026-03-02 00:40:21.000000\", \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Credible practitioner claim from named firm. Production deployment is stated but not independently verified.\"}',NULL,'Production validation claim â€” no external audit; practitioner account','2026-03-02 00:35:28'),(30,'ARK (Agents at Scale Runtime for Kubernetes) is released as open source at github.com/mckinsey/agents-at-scale-ark. It is described as provider-agnostic and codifies patterns from dozens of agentic application projects, including built-in Kubernetes CRDs for agents, models, memory, tools, and evaluation.',5,'case_study','github.com/mckinsey/agents-at-scale-ark','{\"credibility\": 2, \"evaluated_at\": \"2026-03-02 00:40:21.000000\", \"independence\": \"original\", \"verifiability\": \"verified\", \"credibility_notes\": \"GitHub URL is publicly verifiable. ARK repo existence can be confirmed directly.\"}',NULL,NULL,'2026-03-02 00:35:28'),(31,'The two-layer architecture — deterministic orchestration plus bounded agent execution — is described as the consistent pattern across all successful implementations in the QuantumBlack client portfolio.',5,'expert_opinion',NULL,'{\"credibility\": 2, \"evaluated_at\": \"2026-03-02 00:40:21.000000\", \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Expert opinion from practitioner at established firm. Consistent with patterns described across the source. No independent verification available.\"}',NULL,'Asserted without enumerated case count or failure rate','2026-03-02 00:35:28'),(32,'Self-orchestrating agents on larger codebases exhibited specific failure modes: skipped steps, circular dependencies, and analysis loops. These are reported as observed behaviors, not hypothetical risks.',5,'anecdotal',NULL,'{\"credibility\": 3, \"evaluated_at\": \"2026-03-02 00:40:21.000000\", \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Anecdotal observation from client engagements. Specific failure modes are plausible but no benchmarks or controlled comparisons provided. Single practitioner perspective.\"}',NULL,'No quantitative data; practitioner observation from client work','2026-03-02 00:35:28'),(33,'Spec Kit and Kiro share the same key design decision: separating persistent project context from per-feature specifications, both stored in the repository. The source asserts this without citation or detail about how the tools were compared.',5,'expert_opinion',NULL,'{\"credibility\": 3, \"evaluated_at\": \"2026-03-02 00:40:21.000000\", \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Asserted without citation or detail about how the tools were evaluated. The claim may be accurate but is unsubstantiated in the source. Would require independent confirmation against Spec Kit and Kiro documentation.\"}',NULL,'Unverified comparative assertion; source acknowledges no citation provided','2026-03-02 00:35:28'),(34,'The knowledge agent workflow example: during feature creation, a requirements agent calls the knowledge agent multiple times. One documented query: \"Should notifications be sent synchronously or via a queue?\" Logged assumption: \"Using async queue-based delivery (not synchronous).\" These assumptions surface as discrete, structured items in the pull request diff — reviewable and correctable.',5,'case_study','Should notifications be sent synchronously or via a queue?','{\"credibility\": 2, \"evaluated_at\": \"2026-03-02 00:40:21.000000\", \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Concrete example with verbatim quote. Specific enough to be representative of the actual pattern. Illustrative rather than exhaustive.\"}',NULL,'Concrete implementation example with specific query and logged assumption','2026-03-02 00:35:28'),(35,'When a reviewer approves a PR, they approve the logged assumptions alongside the code. When they reject an assumption, the agent reworks with corrected information, and the correction becomes a documented decision that future agents can retrieve.',5,'expert_opinion',NULL,'{\"credibility\": 2, \"evaluated_at\": \"2026-03-02 00:40:21.000000\", \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Describes a coherent and plausible workflow. Verifiable in principle against ARK implementation but not independently confirmed here.\"}',NULL,NULL,'2026-03-02 00:35:28'),(36,'The workflow engine enforces rules including: requirements must be complete before task generation begins; architecture must be reviewed before implementation starts; tasks can only execute when their dependencies are satisfied.',5,'case_study',NULL,'{\"credibility\": 2, \"evaluated_at\": \"2026-03-02 00:40:21.000000\", \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Specific, concrete rules stated by the source. Consistent with the deterministic orchestration architecture described throughout.\"}',NULL,NULL,'2026-03-02 00:35:28'),(37,'Evaluation runs in two sequential layers at end of each phase: (1) deterministic checks — linters, test suites, structural validation including frontmatter presence, required section structure, cross-reference resolution; (2) critic agent for checks requiring judgment. If either layer rejects output, the producing agent iterates until both pass.',5,'case_study',NULL,'{\"credibility\": 2, \"evaluated_at\": \"2026-03-02 00:40:21.000000\", \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Detailed description of evaluation architecture. Specific enough to be actionable. Verifiable in principle against ARK codebase.\"}',NULL,NULL,'2026-03-02 00:35:28'),(38,'Folder and naming conventions (e.g., specs/REQ-001-*/, context/, REQ-* prefixes) serve dual purpose: organizing artifacts for human developers and enabling the workflow engine to parse parent-child relationships and compute task order programmatically.',5,'case_study',NULL,'{\"credibility\": 2, \"evaluated_at\": \"2026-03-02 00:40:21.000000\", \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Specific folder paths and naming patterns provided. Verifiable against ARK repository conventions.\"}',NULL,NULL,'2026-03-02 00:35:28'),(39,'The source explicitly states: no quantitative benchmarks are provided. Performance claims — that deterministic orchestration outperforms self-orchestrating agents, that specialized agents outperform general ones — are presented as patterns observed across client engagements but are not backed by controlled measurements or published data.',5,'expert_opinion',NULL,'{\"credibility\": 1, \"evaluated_at\": \"2026-03-02 00:40:21.000000\", \"independence\": \"original\", \"verifiability\": \"verified\", \"credibility_notes\": \"Source explicitly acknowledges lack of quantitative benchmarks. This is a factually certain statement about what the source does and does not contain â€” highest credibility as a limitation disclosure.\"}',NULL,'Source self-reports this limitation explicitly in Gaps and Caveats section','2026-03-02 00:35:28'),(40,'The source is authored by a QuantumBlack practitioner and prominently references QuantumBlack tooling (ARK). The open-source release of ARK is mentioned in both the introduction and the conclusion, which the source acknowledges introduces potential promotional framing.',5,'expert_opinion',NULL,'{\"credibility\": 1, \"evaluated_at\": \"2026-03-02 00:40:21.000000\", \"independence\": \"original\", \"verifiability\": \"verified\", \"credibility_notes\": \"Source self-reports its own potential promotional framing. Observable and verifiable directly from the source text. Highest credibility as a documented self-disclosure.\"}',NULL,'Source acknowledges potential bias; important credibility qualifier','2026-03-02 00:35:28'),(41,'The post focuses on greenfield feature development and does not address how the patterns apply to legacy codebase migration, incident response, or other development scenarios that do not follow a clean requirements-to-implementation flow.',5,'expert_opinion',NULL,'{\"credibility\": 1, \"evaluated_at\": \"2026-03-02 00:40:21.000000\", \"independence\": \"original\", \"verifiability\": \"verified\", \"credibility_notes\": \"Factually accurate gap statement â€” the source does not address legacy migration or incident response. Verifiable by inspection of source content.\"}',NULL,'Scope limitation explicitly acknowledged by source','2026-03-02 00:35:28'),(42,'Artifact status is tracked in frontmatter (draft, in-review, approved, complete). Folder conventions and naming prefixes allow the workflow engine to parse parent-child relationships and compute task order programmatically, making the system machine-readable without a separate configuration layer.',5,'case_study',NULL,'{\"credibility\": 2, \"evaluated_at\": \"2026-03-02 00:40:21.000000\", \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Specific technical detail about artifact status tracking in frontmatter. Consistent with conventions described elsewhere in the source. Verifiable against ARK implementation.\"}',NULL,NULL,'2026-03-02 00:35:28'),(43,'The specialized agent model is explicitly compared by the source to a microservices architecture — trading one complex system for multiple simpler systems plus the orchestration cost of managing interfaces. This framing positions agent complexity as an architectural problem with established software engineering solutions.',5,'expert_opinion','trading one complex system for multiple simpler systems plus the orchestration cost of managing interfaces between them','{\"credibility\": 2, \"evaluated_at\": \"2026-03-02 00:40:21.000000\", \"independence\": \"original\", \"verifiability\": \"verified\", \"credibility_notes\": \"Verbatim quote from source. The analogy is clearly attributed to the author. Credible as a representation of the author\'s framing.\"}',NULL,NULL,'2026-03-02 00:35:28'),(44,'The source directly counters the popular narrative that more capable models with more autonomy are inherently better, asserting instead that constraints and structure are what enable reliable output — not raw capability.',5,'expert_opinion','value from AI agents comes when they operate inside conventions, structured specifications, and deterministic processes','{\"credibility\": 2, \"evaluated_at\": \"2026-03-02 00:40:21.000000\", \"independence\": \"original\", \"verifiability\": \"verified\", \"credibility_notes\": \"Verbatim quote from source. Accurately captures the author\'s explicit counter-positioning against autonomy-maximalist narratives.\"}',NULL,NULL,'2026-03-02 00:35:28'),(45,'Booch\'s direct quote: \"The entire history of software engineering is one of rising levels of abstraction.\"',6,'expert_opinion','The entire history of software engineering is one of rising levels of abstraction.','{\"credibility\": 2, \"evaluated_at\": \"2026-03-04 04:23:49.000000\", \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Direct verbatim quote from primary expert. Credibility 2 (not 1) because it is an assertion from a single expert, not empirically tested data.\"}',NULL,'Direct quote from co-creator of UML','2026-03-04 04:18:12'),(46,'The IRS still runs IBM 360 Assembly Language on emulators stacked on emulators, with business rules baked into the assembly code itself — a system that predates most modern software practices and cannot be cleanly extracted.',6,'case_study',NULL,'{\"credibility\": 2, \"evaluated_at\": \"2026-03-04 04:23:49.000000\", \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"IRS legacy COBOL/Assembly systems are publicly documented. The specific detail of IBM 360 Assembly on emulators is consistent with widely reported facts about IRS infrastructure.\"}',NULL,'Concrete example of legacy code permanence','2026-03-04 04:18:12'),(47,'The Booch method originated between 1979 and 1981 during consulting work for the Department of Defense on Ada language adoption — over 40 years before this source was recorded, yet the method\'s core abstractions persist in modern OOP.',6,'anecdotal',NULL,'{\"credibility\": 2, \"evaluated_at\": \"2026-03-04 04:23:49.000000\", \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Autobiographical claim from the primary subject. Consistent with published record of Booch method history. Verifiable against published accounts.\"}',NULL,'Historical evidence of long-lived design decisions','2026-03-04 04:18:12'),(48,'Rational Software was acquired by IBM in 2003 for approximately $2.1 billion (Booch cited $2.7B; records suggest $2.1B — figure should be verified). At acquisition, Rational had 3,500 employees across 14 countries and revenues approaching $1 billion.',6,'case_study',NULL,'{\"credibility\": 2, \"evaluated_at\": \"2026-03-04 04:23:49.000000\", \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Acquisition is a documented public event. Distillation correctly flags discrepancy between Booch quote ($2.7B) and other records ($2.1B) â€” credibility held to 2 pending verification of exact figure.\"}',NULL,'Flagged as approximate â€” verify acquisition price before citing','2026-03-04 04:18:12'),(49,'The James Webb Space Telescope uses UML in its design — a contemporary, high-stakes system where the three axes (ceremony, risk, complexity) all score high.',6,'case_study',NULL,'{\"credibility\": 2, \"evaluated_at\": \"2026-03-04 04:23:49.000000\", \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Specific, falsifiable claim about a named system. JWST software development practices are documented in published literature and NASA engineering reports.\"}',NULL,'Evidence that UML persists in high-stakes engineering','2026-03-04 04:18:12'),(50,'Amazon published blog posts describing its use of formal methods for AWS S3 to catch edge cases occurring at one-in-a-billion to one-in-a-trillion frequency — rare in relative terms but regular events at Amazon\'s operational scale.',6,'case_study',NULL,'{\"credibility\": 1, \"evaluated_at\": \"2026-03-04 04:23:49.000000\", \"independence\": \"original\", \"verifiability\": \"verified\", \"credibility_notes\": \"Amazon has publicly published blog posts and papers on use of formal methods (TLA+) for AWS S3. This is a citable, verified case study.\"}',NULL,'Illustrates how scale changes the value equation for formalism','2026-03-04 04:18:12'),(51,'Microsoft used formal methods in driver validation — an example from one of the most defect-sensitive software domains.',6,'case_study',NULL,'{\"credibility\": 2, \"evaluated_at\": \"2026-03-04 04:23:49.000000\", \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Microsoft use of SLAM and formal verification in Windows driver development is publicly documented (Microsoft Research publications).\"}',NULL,NULL,'2026-03-04 04:18:12'),(52,'Booch\'s direct quote on architecture: \"Architecture represents the set of significant design decisions that shape the form and function of a system, where significant is measured by cost of change.\"',6,'expert_opinion','Architecture represents the set of significant design decisions that shape the form and function of a system, where significant is measured by cost of change.','{\"credibility\": 2, \"evaluated_at\": \"2026-03-04 04:23:49.000000\", \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Verbatim quote. This definition is widely cited and traceable to Booch and collaborators. It has become a standard formulation in the field.\"}',NULL,'Primary definition from co-creator of UML','2026-03-04 04:18:12'),(53,'UML 1.0 explicitly describes UML as a visual language for reasoning about, visualizing, specifying, and documenting software-intensive systems — not for generating code. Booch views the UML 2.0 push toward code generation as a profound mistake that made UML unnecessarily complex.',6,'expert_opinion','The UML is a visual language intended to reason about, visualize, specify, and document the artifacts of a software-intensive system. It says nothing about it being a programming language.','{\"credibility\": 1, \"evaluated_at\": \"2026-03-04 04:23:49.000000\", \"independence\": \"original\", \"verifiability\": \"verified\", \"credibility_notes\": \"The UML 1.0 specification is a published document. The verbatim quote is directly traceable to a primary source document. Booch\'s opinion on UML 2.0 is expert opinion from the co-creator.\"}',NULL,NULL,'2026-03-04 04:18:12'),(54,'At its peak around 2000, UML had 20—“30% penetration among commercial developers. High-ceremony, high-risk, high-complexity systems (defense, aerospace, critical infrastructure) still use it; VC-funded startups building on commodity infrastructure generally do not.',6,'expert_opinion',NULL,'{\"credibility\": 3, \"evaluated_at\": \"2026-03-04 04:23:49.000000\", \"independence\": \"original\", \"verifiability\": \"unverifiable\", \"credibility_notes\": \"Expert estimate without citation or methodology. Penetration percentage is not defined (survey-based? tool adoption? self-reported?). Treat as approximate expert recollection.\"}',NULL,'Penetration figure is an expert estimate without citation â€” treat as indicative','2026-03-04 04:18:12'),(55,'Booch describes a three-axis formalism model: (1) ceremony/accountability (startup vs. safety-critical org), (2) risk (cost of failure), (3) complexity (novelty of problem domain). Most modern commercial software sits in the low range on all three axes.',6,'expert_opinion',NULL,'{\"credibility\": 2, \"evaluated_at\": \"2026-03-04 04:23:49.000000\", \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Booch\'s own conceptual framework, presented as a practical guide rather than empirical research. Internally coherent and consistent with published architectural literature.\"}',NULL,'Framework is illustrative, not quantified','2026-03-04 04:18:12'),(56,'A personal cluster of four Nvidia single-board computers carries more processing power than existed in the entire world in the 1970s — Booch\'s illustration of how dramatically computational cost has collapsed.',6,'anecdotal',NULL,'{\"credibility\": 3, \"evaluated_at\": \"2026-03-04 04:23:49.000000\", \"independence\": \"original\", \"verifiability\": \"unverifiable\", \"credibility_notes\": \"Anecdotal illustration. The directional claim (massive cost collapse) is accurate; the specific comparison is imprecise and unverifiable as stated.\"}',NULL,'Rhetorical illustration; not a verified statistic','2026-03-04 04:18:12'),(57,'Booch: \"You will always need people who make informed decisions no matter what the language is.\" — stated in the context of AI code generation tools.',6,'expert_opinion','You will always need people who make informed decisions no matter what the language is.','{\"credibility\": 2, \"evaluated_at\": \"2026-03-04 04:23:49.000000\", \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Direct verbatim quote from expert. Represents expert opinion on human judgment in software engineering. Widely held view in the field.\"}',NULL,NULL,'2026-03-04 04:18:12'),(58,'The object-oriented Booch method over-emphasized inheritance, which led to brittle abstractions — a structural weakness later addressed by design patterns emphasizing composition and interface-based programming.',6,'expert_opinion',NULL,'{\"credibility\": 2, \"evaluated_at\": \"2026-03-04 04:23:49.000000\", \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Self-critical assessment from the method\'s creator. The inheritance-vs-composition tension is well-documented in software engineering literature (Gang of Four, Liskov substitution principle debates).\"}',NULL,'Self-criticism from the creator of the method','2026-03-04 04:18:12'),(59,'The SAGE (Semi-Automatic Ground Environment) system, operational through the 1980s, was the first large-scale software-intensive system and precipitated the 1968 NATO software engineering conference — the event that coined \"software engineering\" as a discipline.',6,'case_study',NULL,'{\"credibility\": 1, \"evaluated_at\": \"2026-03-04 04:23:49.000000\", \"independence\": \"original\", \"verifiability\": \"verified\", \"credibility_notes\": \"The 1968 NATO Software Engineering Conference is a documented historical event. SAGE as a precipitating case study for the conference is consistent with the historical record.\"}',NULL,'Historical evidence of software engineering\'s recurring large-system challenges','2026-03-04 04:18:12'),(60,'Linus Torvalds provides the \"conceptual integrity\" for the Linux kernel; Booch observes that when Torvalds eventually steps back, architectural drift is inevitable — as it is for any system without a sustained chief decision-maker.',6,'expert_opinion',NULL,'{\"credibility\": 2, \"evaluated_at\": \"2026-03-04 04:23:49.000000\", \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Booch\'s application of Brooks\' conceptual integrity concept to Linux is a credible analytical claim. Torvalds\' role as architectural gatekeeper is well-documented.\"}',NULL,'Illustrates the dependency of architectural coherence on human judgment','2026-03-04 04:18:12'),(61,'Booch\'s quote on migration permanence: \"Migrations will plague us until the heat death of the cosmos.\"',6,'expert_opinion','Migrations will plague us until the heat death of the cosmos.','{\"credibility\": 2, \"evaluated_at\": \"2026-03-04 04:23:49.000000\", \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Vivid expert opinion quote. The underlying claim (migrations are permanent) is supported by observable industry history across decades.\"}',NULL,NULL,'2026-03-04 04:18:12'),(62,'The Rational Unified Process, developed primarily by Philippe Kruchten building on Ivar Jacobson\'s work, pioneered incremental and iterative development, continuous integration, and continuous deployment concepts before those terms became standard industry vocabulary.',6,'case_study',NULL,'{\"credibility\": 2, \"evaluated_at\": \"2026-03-04 04:23:49.000000\", \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"RUP\'s iterative development origins are documented in published literature. The claim that RUP preceded modern CI/CD vocabulary is historically supportable, though the direct lineage is contested.\"}',NULL,'Historical evidence that modern practices have long roots','2026-03-04 04:18:12'),(63,'McKinsey surveyed approximately 300 global enterprises on AI productivity outcomes. The average reported productivity improvement at the company level was 5â€“15%, despite high individual-level productivity gains reported by engineers using AI tools.',7,'statistical',NULL,'{\"credibility\": 2, \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"McKinsey proprietary survey of approximately 300 enterprises. Self-reported data with consulting-firm collection bias risk. No methodology published. Credibility is established given McKinsey institutional standards, but cannot reach highest tier without independent replication.\"}',NULL,'McKinsey proprietary survey. Potential self-reporting bias and selection effects. No methodology description provided in the talk.','2026-03-04 06:56:01'),(64,'Top-performing enterprises in the McKinsey survey were 7x more likely to have AI-native workflows spanning four or more SDLC use cases, and 6x more likely to have AI-native roles with smaller, consolidated-skill pods compared to the broader survey population.',7,'statistical',NULL,'{\"credibility\": 2, \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Same McKinsey survey as evidence 63. The 7x and 6x multipliers are striking. Selection bias risk for the top-performer cohort is unaddressed. Methodology for defining top performer is not disclosed.\"}',NULL,'McKinsey proprietary survey differentials. \"Top performer\" definition not fully disclosed in the talk.','2026-03-04 06:56:01'),(65,'Top-performing enterprises in the McKinsey survey reported 5â€“6x improvements in delivery speed and time to market, attributed to structural AI-native changes rather than tool adoption alone.',7,'statistical',NULL,'{\"credibility\": 2, \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Same McKinsey survey as evidence 63. The 5-6x figure is drawn from the same top-performer cohort as evidence 64. The same methodology concerns apply. The figure is internally consistent with the 7x and 6x structural adoption differentials.\"}',NULL,'McKinsey proprietary survey. Same caveats as other survey figures.','2026-03-04 06:56:01'),(66,'Approximately 70% of surveyed enterprises reported no change in developer or PM roles despite widespread AI tool adoption, indicating role definition has not kept pace with capability change.',7,'statistical',NULL,'{\"credibility\": 2, \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Same McKinsey survey as evidence 63. A concrete and verifiable finding. Self-report of role-change status is relatively objective compared to productivity self-reports. Corroborated directionally by the qualitative change management case studies in the same source.\"}',NULL,'McKinsey proprietary survey finding.','2026-03-04 06:56:01'),(67,'A leading international bank ran team-level interventions restructuring sprint sequencing, agent-human role definitions, and squad organization. The results included a 60x increase in agent consumption and a 51% increase in code merges, with improvements tied directly to business priorities.',7,'case_study',NULL,'{\"credibility\": 2, \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Client case study without named institution, which is typical in consulting work. The 60x agent consumption figure is potentially inflated by a very low starting baseline, context not provided. The 51% increase in code merges is a more grounded metric. Results are tied to specific interventions described in detail, which improves traceability.\"}',NULL,'Bank client unnamed. The 60x agent consumption figure may be inflated by a low baseline â€” the talk does not clarify the starting point.','2026-03-04 06:56:01'),(68,'A technology company rolled out AI tools across the product development lifecycle but saw inconsistent and suboptimal usage â€” adoption dropped off even as user count grew, with no aggregate impact improvement. After resetting expectations, implementing hands-on upskilling, bringing coaches into early sprints, and establishing a measurement system, adoption stabilized and impact improved materially.',7,'case_study',NULL,'{\"credibility\": 2, \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Client case study without named institution. The before-and-after narrative (inconsistent adoption, then structured upskilling, then improved adoption) is behaviorally coherent and specific. No quantitative outcome metrics are provided for this case study, limiting precision. The pattern described is consistent with change management literature broadly.\"}',NULL,'Company unnamed. Illustrates failure mode of tool rollout without change management support.','2026-03-04 06:56:01'),(69,'A client operating on a standard two-pizza team model ran experiments with smaller, consolidated-role pods. The result was more teams from the same headcount, with maintained or improved code quality and significant speed improvements.',7,'case_study',NULL,'{\"credibility\": 2, \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Client case study without named institution. Describes a specific experimental design (two-pizza to consolidated pods) with reported outcomes: more teams, same headcount, maintained quality, speed improvement. The outcome claims are directional rather than quantified, which limits precision.\"}',NULL,'Client unnamed. Evidence for pod consolidation claim.','2026-03-04 06:56:01'),(70,'Bottom-performing enterprises in the McKinsey survey were not measuring delivery speed at all, and only 10% of surveyed enterprises were measuring productivity.',7,'statistical',NULL,'{\"credibility\": 2, \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Same McKinsey survey as evidence 63. The 10% figure is specific and striking. Measurement of what organizations measure is relatively straightforward to survey accurately, making this finding more reliable than productivity outcome self-reports.\"}',NULL,'McKinsey proprietary survey. Quantifies the measurement gap among low performers.','2026-03-04 06:56:01'),(71,'A Carnegie Mellon research report identified AI-accelerated code generation as a factor amplifying technical debt and codebase complexity.',7,'empirical',NULL,'{\"credibility\": 2, \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"External empirical research cited from Carnegie Mellon. The citation is brief and lacks report title, authors, or date, making independent verification difficult. The institutional source carries strong academic credibility. The finding that AI-accelerated code generation amplifies technical debt is directionally consistent with practitioner experience and has face validity.\"}',NULL,'Cited without full citation detail in the talk â€” independent verification difficult. Brief mention only.','2026-03-04 06:56:01'),(72,'The shift to agile required restructuring teams, ceremonies, and roles â€” not just adopting new practices on top of existing structures. This analogy, drawn from the speaker\'s personal experience during the agile transition approximately 20 years ago, frames the AI-native transition as requiring equivalent structural change.',7,'anecdotal',NULL,'{\"credibility\": 3, \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Personal anecdote from the speaker about the agile transition approximately 20 years ago. Illustrative but not probative. The analogy that structural change is required for technology paradigm shifts is historically sound as a framing device, but the evidence type is anecdotal and carries the lowest credibility tier. Useful for contextualization, not for independent verification of claims.\"}',NULL,'Rhetorical framing device from Harrysson\'s direct experience. Not empirical evidence.','2026-03-04 06:56:01'),(73,'Point-solution adoption without workflow integration, and workflow integration without role and team structure change, are both failure modes producing only marginal gains. Outsized gains require all three layers of change simultaneously.',7,'expert_opinion',NULL,'{\"credibility\": 2, \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Reasoned expert opinion from McKinsey partners with extensive enterprise consulting experience in AI adoption. The three-layer model (tools, workflows, roles) is a structured analytical argument rather than empirical evidence. Credibility is established given the practitioners have direct access to the case study data supporting the framework.\"}',NULL,'Analytical framework from McKinsey presenters. Not empirically validated in the talk itself.','2026-03-04 06:56:01'),(74,'The McKinsey measurement framework covers inputs (coding tool investment, upskilling time, change management investment), direct outputs (AI adoption breadth and depth, velocity, capacity), quality outputs (developer NPS, code security, code quality, resilience), and economic outcomes (time to revenue, price differential for higher-quality features, customer expansion, cost reduction per pod).',7,'expert_opinion',NULL,'{\"credibility\": 2, \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Expert opinion representing a consulting-developed framework. The MECE structure is rigorous and the coverage (inputs, outputs, quality outputs, economic outcomes) is comprehensive. Not empirically validated as a predictive framework. It is a proposed measurement architecture. Credibility is established given the practitioner basis and logical coherence.\"}',NULL,'McKinsey MECE framing. Speakers acknowledge the framework is still maturing as tools evolve.','2026-03-04 06:56:01'),(75,'Change management for AI adoption requires getting 20 to 30 things right simultaneously â€” communication, incentives, upskilling, and measurement â€” positioning it as continuous operational discipline rather than a single transformation initiative.',7,'expert_opinion',NULL,'{\"credibility\": 2, \"independence\": \"original\", \"verifiability\": \"verifiable\", \"credibility_notes\": \"Expert opinion from McKinsey partners on change management requirements. The 20-30 things framing is experiential and directional rather than a formally defined list. The tech company case study in evidence 68 provides supporting illustration. Credibility is established given the practitioner experience base and consistency with change management literature.\"}',NULL,'Explicit framing from the McKinsey talk. No single lever is sufficient.','2026-03-04 06:56:01');
