LOCK TABLES `methods` WRITE;
/*!40000 ALTER TABLE `methods` DISABLE KEYS */;
INSERT INTO `methods` VALUES (1,'Automated expert panel evaluation â€” a model that connects to git repositories and analyzes source code changes at the commit level, validated against 10â€“15 independent engineering experts who evaluate each change across quality, maintainability, output volume, and difficulty.',2,'metric',NULL,'2026-03-03 04:00:18'),(2,'The gross-vs-net productivity decomposition â€” measuring total output (added functionality + refactoring + rework + deletions) then subtracting definitionally wasteful rework to isolate useful output.',2,'framework',NULL,'2026-03-03 04:00:18'),(3,'Ask LLMs the same question multiple times with wording variations, then compare answers to extract signal from variation â€” a practical technique for managing hallucination risk in numeric or factual queries.',3,'technique',NULL,'2026-03-03 04:00:58'),(4,'Never use an LLM to calculate answers that can be computed deterministically; instead, ask the LLM to generate code that performs the calculation.',3,'practice',NULL,'2026-03-03 04:00:58'),(5,'Task decomposition as a security pattern â€” separating privileged sessions (codebase analysis) from lower-privilege sessions (external research) with human review gates between each stage, applying the Principle of Least Privilege at the session level.',4,'process',NULL,'2026-03-03 04:01:45'),(6,'Container sandboxing â€” running LLM agents inside Docker containers with only project source code mounted and network access restricted by firewall rules, or running MCP servers in individual containers to isolate third-party code.',4,'technique',NULL,'2026-03-03 04:01:45'),(7,'MCP server vetting checklist: actively maintained? open-source with reviewable code? responsive issue tracker for security? acceptable license? transmits data externally? what does vendor collect?',4,'framework',NULL,'2026-03-03 04:01:45'),(8,'Credential hygiene for LLM agents: never store production credentials in files; use environment variables or 1Password CLI to keep credentials in memory only; use temporary privilege escalation and read-only tokens.',4,'practice',NULL,'2026-03-03 04:01:45'),(9,'Network allow-listing â€” building and enforcing an allow-list of acceptable outbound destinations to constrain the external communication leg of the trifecta.',4,'technique',NULL,'2026-03-03 04:01:45'),(10,'Spec-driven development (SDD) â€” separating persistent project context from per-feature specifications, both stored in the repository, with artifact status tracked in frontmatter (draft, in-review, approved, complete) and folder/naming conventions enabling programmatic parsing of relationships and task order.',5,'framework',NULL,'2026-03-03 04:02:35'),(11,'Two-layer architecture â€” deterministic orchestration layer (workflow engine with predefined rules for phase transitions) plus bounded agent execution layer (agents operating within well-defined problem spaces).',5,'framework',NULL,'2026-03-03 04:02:35'),(12,'Two-layer evaluation â€” deterministic checks first (linters, test suites, structural validation) followed by critic agent evaluation for judgment-requiring checks, with rejection triggering agent iteration until both layers pass.',5,'process',NULL,'2026-03-03 04:02:35'),(13,'Knowledge agent pattern â€” a specialized agent that other agents call as a tool when encountering uncertainty, logging assumptions and decisions as structured items that accumulate as institutional memory inside the repository, surfaced through version control.',5,'technique',NULL,'2026-03-03 04:02:35'),(14,'The Three-Axis Formalism Model: evaluate whether UML or formal methods are appropriate by scoring a project on three dimensions â€” (1) ceremony/accountability requirements, (2) cost of failure/risk, and (3) novelty and complexity of the problem domain. High scores on all three axes justify the overhead of formal modeling.',6,'framework','Booch\'s practical framework for architectural rigor decisions','2026-03-04 04:20:12'),(15,'The Booch Method of object-oriented decomposition: structure software systems by classes and objects rather than by algorithms. Influenced by Liskov\'s abstract data types, Parnas\'s information hiding, and Dijkstra and Hoare\'s theoretical foundations.',6,'framework','Historical methodology; basis for modern OOP practices','2026-03-04 04:20:12'),(16,'The 4+1 View Model of software architecture (Philippe Kruchten, standardized as IEEE/IEC/ISO 42220): describe a system using five views â€” use cases, logical, process, implementation, and deployment. Use cases serve as the organizing scenario that ties the other four views together.',6,'framework','Now an international standard for architectural description','2026-03-04 04:20:12'),(17,'UML as a visual communication and reasoning tool (not code generator): use UML diagrams to reason about, specify, and document the significant design decisions in a software system â€” particularly for high-ceremony, high-risk, or high-complexity systems.',6,'practice',NULL,'2026-03-04 04:20:12'),(18,'Formal methods for ultra-high-reliability software: apply mathematical specification and model checking to catch edge-case failures that occur at one-in-a-billion or one-in-a-trillion frequencies â€” as Amazon used for AWS S3 and Microsoft used for driver validation.',6,'technique',NULL,'2026-03-04 04:20:12'),(19,'A structured approach to transitioning enterprise software teams from agile to AI-native operations, covering three layers: workflow integration (4+ SDLC use cases), role restructuring (consolidated pods), and change management (20â€“30 simultaneous adjustments). The framework positions these three layers as jointly necessary for outsized results.',7,'framework','McKinsey AI-native transformation framework. Not yet empirically validated as a complete model.','2026-03-04 07:00:14'),(20,'Replacing traditional 8â€“10 person two-pizza teams with 3â€“5 person pods where engineers hold consolidated full-stack roles with agent orchestration skills. Run as client experiments before full adoption. Validated through headcount-neutral team multiplication and speed improvements.',7,'process','Product-builder pod model. Tested via client experiment.','2026-03-04 07:00:14'),(21,'A change management practice embedding coaches into early sprints, running \"bring your own code\" sessions, establishing code labs and certification programs, resetting expectations, and measuring adoption depth and breadth â€” used to stabilize inconsistent AI tool adoption.',7,'practice','Sprint-level AI adoption coaching. Demonstrated in tech company case study.','2026-03-04 07:00:14'),(22,'A four-layer measurement system covering inputs (tool investment, upskilling time, change management investment), direct outputs (adoption breadth and depth, velocity, capacity), quality outputs (developer NPS, code security, code quality, resilience via mean time to resolve priority bugs), and economic outcomes (time to revenue, price differential, customer expansion, cost per pod).',7,'metric','MECE AI productivity measurement framework. Acknowledged as still maturing.','2026-03-04 07:00:14'),(23,'A decision framework for choosing between a factory-of-agents model (for legacy modernization with well-defined outputs and high context requirements) and an iterative co-creator loop (for greenfield and brownfield new features where non-deterministic variation benefits the outcome).',7,'framework','Task-type human-agent model segmentation. Asserted without supporting empirical data.','2026-03-04 07:00:14');
