INSERT INTO `publications` VALUES (1,'AI Engineer','other',NULL,'2026-03-02 15:57:03'),(2,'Martin Fowler','other',NULL,'2026-03-02 15:57:03'),(3,'Medium','other',NULL,'2026-03-02 15:57:03'),(5,'The Pragmatic Engineer','other',NULL,'2026-03-04 04:10:42');
