INSERT INTO `topics` VALUES (1,'AI-Assisted Development','How AI tools affect software development workflows, productivity, and code quality.',7,'2026-03-01 20:28:43'),(2,'Productivity Measurement','Methods, metrics, and challenges in measuring developer productivity.',1,'2026-03-01 20:28:43'),(3,'LLM Capabilities and Limitations','Technical constraints and performance characteristics of large language models in coding contexts.',7,'2026-03-01 20:28:43'),(4,'AI Industry and Economics','The business, investment, and market dynamics around AI technology.',7,'2026-03-01 21:55:56'),(5,'AI Security and Risk','Security vulnerabilities, attack surfaces, and risk management for AI systems.',7,'2026-03-01 21:55:56'),(6,'Agentic Workflows','Patterns for structuring AI agent systems in software development: orchestration, agent architecture, spec-driven development, evaluation pipelines, and conventions.',1,'2026-03-02 22:41:56'),(7,'AI',NULL,NULL,'2026-03-02 23:22:13'),(8,'Software Architecture','Architectural decisions, patterns, trade-offs, and the evolving role of the software architect',NULL,'2026-03-04 04:53:11'),(9,'Legacy Code and Software Migration','Managing long-lived codebases, migration strategies, and the economics of software longevity',NULL,'2026-03-04 04:53:11'),(10,'Software Engineering History and Evolution','How the discipline has evolved through paradigm shifts â€” from structured programming to objects to distributed systems to AI',NULL,'2026-03-04 04:53:11'),(11,'AI Operating Models and Team Transformation','Structural reorganization required to capture AI value: team sizing, role consolidation, AI-native pods, and workflow redesign.',1,'2026-03-04 07:01:56'),(12,'AI Adoption and Change Management','Organizational change management required for successful AI adoption: communication, incentives, upskilling, measurement, and getting multiple factors right simultaneously.',1,'2026-03-04 07:01:56');
